impl<S> ProcessVmm<S>
where
    S: InstanceStartExecutor,
{
    #[cfg(test)]
    pub(crate) fn instance_info(&self) -> &InstanceInfo {
        self.controller.instance_info()
    }

    #[cfg(test)]
    pub(crate) fn drive_configs(&self) -> &[DriveConfig] {
        self.controller.drive_configs()
    }

    #[cfg(test)]
    pub(crate) fn network_interface_configs(&self) -> &[NetworkInterfaceConfig] {
        self.controller.network_interface_configs()
    }

    #[cfg(test)]
    pub(crate) const fn machine_config(&self) -> MachineConfig {
        self.controller.machine_config()
    }

    #[cfg(test)]
    pub(crate) fn has_custom_cpu_template(&self) -> bool {
        self.controller.custom_cpu_template().is_some()
    }

    #[cfg(test)]
    pub(crate) fn boot_source_config(&self) -> Option<&BootSourceConfig> {
        self.controller.boot_source_config()
    }

    #[cfg(test)]
    pub(crate) const fn serial_config(&self) -> &SerialConfig {
        self.controller.serial_config()
    }

    pub(crate) fn handle_action(&mut self, action: VmmAction) -> Result<VmmData, VmmActionError> {
        let had_started_session = self.has_started_session();
        let result = match action {
            VmmAction::InstanceStart => self.start_instance(),
            VmmAction::PutBootSource(input) => self.put_boot_source(input),
            VmmAction::PutDrive(input) => self.put_drive(input),
            VmmAction::PutMemoryHotplug(input) => self.put_memory_hotplug(input),
            VmmAction::PutLogger(input) => self.put_logger(input),
            VmmAction::PutMetrics(input) => self.put_metrics(input),
            VmmAction::PutNetworkInterface(input) => self.put_network_interface(input),
            VmmAction::PutPmem(input) => self.put_pmem(input),
            VmmAction::PutSerial(input) => self.put_serial(input),
            VmmAction::PutVsock(input) => self.put_vsock(input),
            VmmAction::Pause => self.pause_instance(),
            VmmAction::Resume => self.resume_instance(),
            VmmAction::CreateSnapshot(input) => self.create_snapshot(input),
            VmmAction::LoadSnapshot(input) => self.load_snapshot(input),
            VmmAction::UpdateBlockDevice(input) => self.update_block_device(input),
            VmmAction::HotUnplugDevice(input) if input.kind() == HotUnplugDeviceKind::Drive => {
                self.remove_drive(input.id())
            }
            VmmAction::HotUnplugDevice(input) if input.kind() == HotUnplugDeviceKind::Pmem => {
                self.remove_pmem(input.id())
            }
            VmmAction::HotUnplugDevice(input)
                if input.kind() == HotUnplugDeviceKind::NetworkInterface =>
            {
                self.remove_network_interface(input.id())
            }
            VmmAction::UpdateNetworkInterface(input) => self.update_network_interface(input),
            VmmAction::PatchPmem(input) => self.update_pmem(input),
            VmmAction::PatchBalloon(input) => self.update_balloon(input),
            VmmAction::PatchBalloonStats(input) => self.update_balloon_statistics(input),
            VmmAction::PatchMemoryHotplug(input) => self.update_memory_hotplug(input),
            VmmAction::GetMemoryHotplug => self.memory_hotplug_status(),
            VmmAction::GetBalloonStats => self.balloon_stats(),
            VmmAction::GetBalloonHintingStatus => self.balloon_hinting_status(),
            VmmAction::PatchBalloonHintingStart(input) => self.start_balloon_hinting(input),
            VmmAction::PatchBalloonHintingStop => self.stop_balloon_hinting(),
            VmmAction::FlushMetrics => self.flush_metrics(),
            action => self.controller.handle_action(action),
        };

        if !had_started_session && self.has_started_session() {
            debug_assert!(self.metrics_session_epoch.is_none());
            self.metrics_session_epoch.get_or_insert_with(Instant::now);
        }

        result
    }

    fn handle_put_action_request(&mut self, action: VmmAction) -> Result<VmmData, VmmActionError> {
        self.controller.record_put_actions_request();
        let result = self.handle_action(action);
        if result.is_err() {
            self.controller.record_put_actions_failure();
        }
        result
    }

    fn handle_get_request(&mut self, request: GetApiRequest) -> Result<VmmData, VmmActionError> {
        request.record(&mut self.controller);
        self.handle_action(request.action())
    }

    fn handle_patch_request(
        &mut self,
        request: PatchApiRequest,
    ) -> Result<VmmData, VmmActionError> {
        let kind = request.kind;
        request.record_request(&mut self.controller);
        let action = request.into_action();
        let result = self.handle_action(action);
        if result.is_err() {
            kind.record_failure(&mut self.controller);
        }
        result
    }

    fn handle_put_request(&mut self, request: PutApiRequest) -> Result<VmmData, VmmActionError> {
        let kind = request.kind;
        request.record_request(&mut self.controller);
        let action = request.into_action();
        let result = self.handle_action(action);
        if result.is_err() {
            kind.record_failure(&mut self.controller);
        }
        result
    }

    fn record_api_request_parse_failure(&mut self, request: ApiRequestMetricParseFailure) {
        request.record(&mut self.controller);
    }

    fn record_put_actions_request(&mut self) {
        self.controller.record_put_actions_request();
    }

    fn record_deprecated_api_call(&mut self) {
        self.controller.record_deprecated_api_call();
    }

    #[track_caller]
    fn log_api_request(&mut self, method: &str, path: impl fmt::Display) -> bool {
        self.controller.log_api_request(method, path)
    }

    fn record_pause_vm_latency_us(&mut self, duration_us: u64) {
        self.controller.record_pause_vm_latency_us(duration_us);
    }

    fn record_resume_vm_latency_us(&mut self, duration_us: u64) {
        self.controller.record_resume_vm_latency_us(duration_us);
    }

    fn record_full_create_snapshot_latency_us(&mut self, duration_us: u64) {
        self.controller
            .record_full_create_snapshot_latency_us(duration_us);
    }

    fn record_diff_create_snapshot_latency_us(&mut self, duration_us: u64) {
        self.controller
            .record_diff_create_snapshot_latency_us(duration_us);
    }

    fn record_load_snapshot_latency_us(&mut self, duration_us: u64) {
        self.controller.record_load_snapshot_latency_us(duration_us);
    }

    #[cfg(target_os = "macos")]
    fn preflight_contained_startup_resources(&self) -> Result<(), VmmActionError> {
        let Some(grant_authority) = &self.grant_authority else {
            return Ok(());
        };
        if !grant_authority.is_active() {
            return Err(VmmActionError::ResourceGrant);
        }

        let boot_uses_grants = self
            .controller
            .boot_source_config()
            .map(|config| {
                let kernel = grant_reference_id(config.kernel_image_path())?.is_some();
                let initrd = config
                    .initrd_path()
                    .map(grant_reference_id)
                    .transpose()?
                    .flatten()
                    .is_some();
                Ok::<_, GrantClaimError>(kernel || initrd)
            })
            .transpose()
            .map_err(|_| VmmActionError::ResourceGrant)?
            .unwrap_or(false);
        if !matches!(
            (&self.boot_grant_state, boot_uses_grants),
            (BootGrantState::Prepared(_), true) | (BootGrantState::PathBased, false)
        ) {
            return Err(VmmActionError::ResourceGrant);
        }

        let mut expected_file_drives = 0_usize;
        let mut expected_vhost_drives = 0_usize;
        let directory_authority = self.directory_grant_authority.as_ref();
        for config in self.controller.drive_configs() {
            match config.backend() {
                DriveBackendConfig::File { path_on_host, .. } => {
                    let tagged = grant_reference_id(path_on_host)
                        .map_err(|_| VmmActionError::ResourceGrant)?
                        .is_some();
                    expected_file_drives += usize::from(tagged);
                    if tagged
                        != matches!(
                            self.drive_grant_states.get(config.drive_id()),
                            Some(BackingGrantState::Prepared(_))
                        )
                    {
                        return Err(VmmActionError::ResourceGrant);
                    }
                }
                DriveBackendConfig::VhostUser { socket } => {
                    expected_vhost_drives += 1;
                    let authority = directory_authority.ok_or(VmmActionError::ResourceGrant)?;
                    let lease = self
                        .vhost_user_grant_states
                        .get(config.drive_id())
                        .ok_or(VmmActionError::ResourceGrant)?;
                    if !authority
                        .validates_vhost_user_lease(socket, lease)
                        .map_err(|_| VmmActionError::ResourceGrant)?
                    {
                        return Err(VmmActionError::ResourceGrant);
                    }
                }
            }
        }
        if self.drive_grant_states.len() != expected_file_drives
            || self.vhost_user_grant_states.len() != expected_vhost_drives
        {
            return Err(VmmActionError::ResourceGrant);
        }

        let mut expected_pmem = 0_usize;
        for config in self.controller.pmem_configs() {
            let tagged = grant_reference_id(Path::new(config.path_on_host()))
                .map_err(|_| VmmActionError::ResourceGrant)?
                .is_some();
            expected_pmem += usize::from(tagged);
            if tagged
                != matches!(
                    self.pmem_grant_states.get(config.id()),
                    Some(BackingGrantState::Prepared(_))
                )
            {
                return Err(VmmActionError::ResourceGrant);
            }
        }
        if self.pmem_grant_states.len() != expected_pmem {
            return Err(VmmActionError::ResourceGrant);
        }

        let serial_uses_grant = self
            .controller
            .serial_config()
            .serial_out_path()
            .map(grant_reference_id)
            .transpose()
            .map_err(|_| VmmActionError::ResourceGrant)?
            .flatten()
            .is_some();
        if !matches!(
            (&self.serial_grant_state, serial_uses_grant),
            (SerialGrantState::Prepared(_), true) | (SerialGrantState::PathBased, false)
        ) {
            return Err(VmmActionError::ResourceGrant);
        }

        let expected_vsock = self
            .controller
            .vsock_config()
            .map(|config| socket_directory_reference(config.uds_path()))
            .transpose()
            .map_err(|_| VmmActionError::ResourceGrant)?
            .flatten();
        match (&self.vsock_grant_state, expected_vsock) {
            (VsockGrantState::PathBased, None) => {}
            (VsockGrantState::Prepared(claim), Some((grant_id, child)))
                if claim.grant_id == grant_id && claim.child == child => {}
            _ => return Err(VmmActionError::ResourceGrant),
        }

        if expected_vhost_drives > 0 {
            let authority = directory_authority.ok_or(VmmActionError::ResourceGrant)?;
            if !authority.is_active() {
                return Err(VmmActionError::ResourceGrant);
            }
            self.vhost_user_broker_authority
                .as_ref()
                .ok_or(VmmActionError::ResourceGrant)?
                .preflight()
                .map_err(|_| VmmActionError::ResourceGrant)?;
        }
        Ok(())
    }

    fn start_instance(&mut self) -> Result<VmmData, VmmActionError> {
        self.controller.preflight_instance_start()?;
        validate_process_vmnet_authority(&self.controller, self.vmnet_authority)
            .map_err(process_vmnet_authority_action_error)?;
        #[cfg(target_os = "macos")]
        let vsock_grant_consumed = matches!(self.vsock_grant_state, VsockGrantState::Consumed);
        #[cfg(not(target_os = "macos"))]
        let vsock_grant_consumed = false;
        if matches!(self.boot_grant_state, BootGrantState::Consumed)
            || self
                .drive_grant_states
                .values()
                .any(|state| matches!(state, BackingGrantState::Consumed))
            || self
                .pmem_grant_states
                .values()
                .any(|state| matches!(state, BackingGrantState::Consumed))
            || matches!(self.serial_grant_state, SerialGrantState::Consumed)
            || vsock_grant_consumed
        {
            return Err(VmmActionError::ResourceGrant);
        }
        #[cfg(target_os = "macos")]
        self.preflight_contained_startup_resources()?;
        let mut vhost_user_block_frontends = BTreeMap::new();
        for config in self
            .controller
            .drive_configs()
            .iter()
            .filter(|config| config.is_vhost_user())
        {
            let socket = config.socket().ok_or({
                VmmActionError::InstanceStart(BackendError::InvalidState(
                    "vhost-user drive has no socket",
                ))
            })?;
            #[cfg(target_os = "macos")]
            let stream = if self.grant_authority.is_some() {
                let lease = self
                    .vhost_user_grant_states
                    .get(config.drive_id())
                    .ok_or(VmmActionError::ResourceGrant)?;
                self.vhost_user_broker_authority
                    .as_ref()
                    .ok_or(VmmActionError::ResourceGrant)?
                    .connect(lease.grant_id(), lease.child())
                    .map_err(|source| {
                        VmmActionError::InstanceStart(BackendError::Hypervisor(source.to_string()))
                    })?
            } else {
                direct_vhost_user::connect(socket, DIRECT_VHOST_USER_OPERATION_TIMEOUT).map_err(
                    |source| {
                        VmmActionError::InstanceStart(BackendError::Hypervisor(source.to_string()))
                    },
                )?
            };
            #[cfg(not(target_os = "macos"))]
            let stream = direct_vhost_user::connect(socket, DIRECT_VHOST_USER_OPERATION_TIMEOUT)
                .map_err(|source| {
                    VmmActionError::InstanceStart(BackendError::Hypervisor(source.to_string()))
                })?;
            let frontend = PreparedVhostUserBlockFrontend::discover(
                stream,
                config.cache_type(),
                DIRECT_VHOST_USER_OPERATION_TIMEOUT,
            )
            .map_err(|source| {
                VmmActionError::InstanceStart(BackendError::Hypervisor(source.to_string()))
            })?;
            if vhost_user_block_frontends
                .insert(config.drive_id().to_string(), frontend)
                .is_some()
            {
                return Err(VmmActionError::InstanceStart(BackendError::InvalidState(
                    "duplicate vhost-user drive resource",
                )));
            }
        }
        let boot_files =
            match std::mem::replace(&mut self.boot_grant_state, BootGrantState::Consumed) {
                BootGrantState::PathBased => {
                    self.boot_grant_state = BootGrantState::PathBased;
                    BootSourceFiles::default()
                }
                BootGrantState::Prepared(files) => files,
                BootGrantState::Consumed => return Err(VmmActionError::ResourceGrant),
            };
        let mut block_backings = BTreeMap::new();
        for (drive_id, state) in &mut self.drive_grant_states {
            let backing = match std::mem::replace(state, BackingGrantState::Consumed) {
                BackingGrantState::Prepared(backing) => backing,
                BackingGrantState::Consumed => return Err(VmmActionError::ResourceGrant),
            };
            let previous = block_backings.insert(drive_id.clone(), backing);
            debug_assert!(previous.is_none());
        }
        let mut pmem_backings = BTreeMap::new();
        for (pmem_id, state) in &mut self.pmem_grant_states {
            let backing = match std::mem::replace(state, BackingGrantState::Consumed) {
                BackingGrantState::Prepared(backing) => backing,
                BackingGrantState::Consumed => return Err(VmmActionError::ResourceGrant),
            };
            let previous = pmem_backings.insert(pmem_id.clone(), backing);
            debug_assert!(previous.is_none());
        }
        let serial_output =
            match std::mem::replace(&mut self.serial_grant_state, SerialGrantState::Consumed) {
                SerialGrantState::PathBased => {
                    self.serial_grant_state = SerialGrantState::PathBased;
                    None
                }
                SerialGrantState::Prepared(output) => Some(output),
                SerialGrantState::Consumed => return Err(VmmActionError::ResourceGrant),
            };
        #[cfg(target_os = "macos")]
        let prepared_vsock =
            match std::mem::replace(&mut self.vsock_grant_state, VsockGrantState::Consumed) {
                VsockGrantState::PathBased => {
                    self.vsock_grant_state = VsockGrantState::PathBased;
                    None
                }
                VsockGrantState::Prepared(claim) => Some(claim),
                VsockGrantState::Consumed | VsockGrantState::Active(_) => {
                    return Err(VmmActionError::ResourceGrant);
                }
            };
        let mut startup_resources =
            VmStartupResources::new(boot_files, block_backings, pmem_backings)
                .with_vhost_user_block_frontends(vhost_user_block_frontends);
        if let Some(serial_output) = serial_output {
            startup_resources = startup_resources.with_serial_output(serial_output);
        }
        #[cfg(target_os = "macos")]
        let mut active_vsock_guard = None;
        #[cfg(target_os = "macos")]
        if let Some(claim) = prepared_vsock {
            let namespace = self
                .socket_namespace
                .as_ref()
                .ok_or(VmmActionError::ResourceGrant)?
                .try_clone()
                .map_err(|_| VmmActionError::ResourceGrant)?;
            let broker = self
                .socket_broker_authority
                .as_ref()
                .ok_or(VmmActionError::ResourceGrant)?
                .take_endpoint()
                .map_err(|_| VmmActionError::ResourceGrant)?;
            let socket = bind_anchored_socket(
                namespace,
                claim,
                ResourceRole::VsockSocketDirectory,
                Some(broker),
            )
            .map_err(|_| VmmActionError::ResourceGrant)?;
            let (listener, guard, connector) = socket
                .into_vsock_parts()
                .map_err(|_| VmmActionError::ResourceGrant)?;
            startup_resources = startup_resources.with_supplied_vsock_listener(
                SuppliedVsockListener::new(listener).with_guest_connector(connector),
            );
            active_vsock_guard = Some(guard);
        }
        let controller = &mut self.controller;
        let starter = &mut self.starter;
        let vmnet_authority = self.vmnet_authority;
        let mut started_session = None;
        let mut terminal_start_failure = false;

        let result = controller.start_instance_with(|controller| {
            match starter.start_with_startup_resources(
                controller,
                vmnet_authority,
                startup_resources,
            ) {
                Ok(session) => {
                    started_session = Some(session);
                    Ok(())
                }
                Err(source) => {
                    terminal_start_failure =
                        source.disposition() == InstanceStartDisposition::Terminal;
                    Err(source.into_source())
                }
            }
        });

        if terminal_start_failure {
            self.terminal_instance_start_failure = true;
        }

        match result {
            Ok(data) => match started_session {
                Some(session) => {
                    self.started_session = Some(session);
                    #[cfg(target_os = "macos")]
                    if let Some(guard) = active_vsock_guard.take() {
                        self.vsock_grant_state = VsockGrantState::Active(guard);
                    }
                    Ok(data)
                }
                None => Err(VmmActionError::InstanceStart(BackendError::InvalidState(
                    "startup executor completed without a session",
                ))),
            },
            Err(err) => Err(err),
        }
    }

    fn put_boot_source(&mut self, input: BootSourceConfigInput) -> Result<VmmData, VmmActionError> {
        let config = self.controller.prepare_boot_source_config(input)?;
        let boot_files = match &self.grant_authority {
            Some(authority) => authority
                .claim_boot_files(config.kernel_image_path(), config.initrd_path())
                .map_err(|_| VmmActionError::ResourceGrant)?,
            None => BootSourceFiles::default(),
        };
        let grant_state = if boot_files.is_empty() {
            BootGrantState::PathBased
        } else {
            BootGrantState::Prepared(boot_files)
        };

        self.controller.commit_boot_source_config(config);
        self.boot_grant_state = grant_state;
        Ok(VmmData::Empty)
    }

    fn put_drive(&mut self, input: DriveConfigInput) -> Result<VmmData, VmmActionError> {
        if self.controller.instance_info().state != bangbang_runtime::InstanceState::NotStarted {
            if let Some(existing_is_vhost_user) = self
                .controller
                .drive_configs()
                .iter()
                .find(|config| config.drive_id() == input.path_drive_id())
                .map(DriveConfig::is_vhost_user)
            {
                if existing_is_vhost_user {
                    return self.insert_runtime_drive(input);
                }
                return self.replace_runtime_drive(input);
            }
            return self.insert_runtime_drive(input);
        }
        let config = self.controller.prepare_drive_config(input)?;
        #[cfg(target_os = "macos")]
        let prepared_vhost_claim: Option<PreparedVhostUserSocketClaim> =
            if config.is_vhost_user() && self.grant_authority.is_some() {
                if self.vhost_user_broker_authority.is_none() {
                    return Err(VmmActionError::ResourceGrant);
                }
                Some(
                    self.directory_grant_authority
                        .as_ref()
                        .ok_or(VmmActionError::ResourceGrant)?
                        .prepare_vhost_user_socket(
                            config.socket().ok_or(VmmActionError::ResourceGrant)?,
                        )
                        .map_err(|_| VmmActionError::ResourceGrant)?
                        .ok_or(VmmActionError::ResourceGrant)?,
                )
            } else {
                None
            };
        let mut grant_claim: Option<PreparedDriveBackingClaim> =
            match (&self.grant_authority, config.backend()) {
                (
                    Some(authority),
                    DriveBackendConfig::File {
                        path_on_host,
                        is_read_only,
                        ..
                    },
                ) => authority
                    .prepare_drive_backing_claim(
                        path_on_host,
                        grant_access_for_read_only(*is_read_only),
                    )
                    .map_err(|_| VmmActionError::ResourceGrant)?,
                (None, _) | (Some(_), DriveBackendConfig::VhostUser { .. }) => None,
            };
        let backing = match (grant_claim.as_mut(), config.backend()) {
            (Some(claim), DriveBackendConfig::File { is_read_only, .. }) => Some(
                claim
                    .take_backing(*is_read_only)
                    .map_err(|_| VmmActionError::ResourceGrant)?,
            ),
            _ => None,
        };
        let drive_id = config.drive_id().to_string();
        let is_vhost_user = config.is_vhost_user();
        #[cfg(target_os = "macos")]
        let vhost_lease = prepared_vhost_claim.map(PreparedVhostUserSocketClaim::commit);

        self.controller.commit_drive_config(config);
        match backing {
            Some(backing) => {
                self.drive_grant_states
                    .insert(drive_id.clone(), BackingGrantState::Prepared(backing));
            }
            None => {
                self.drive_grant_states.remove(&drive_id);
            }
        }
        #[cfg(target_os = "macos")]
        match vhost_lease {
            Some(lease) => {
                self.vhost_user_grant_states.insert(drive_id.clone(), lease);
            }
            None => {
                self.vhost_user_grant_states.remove(&drive_id);
            }
        }
        #[cfg(not(target_os = "macos"))]
        let _ = is_vhost_user;
        #[cfg(target_os = "macos")]
        debug_assert!(
            self.grant_authority.is_none()
                || is_vhost_user == self.vhost_user_grant_states.contains_key(&drive_id)
        );
        if let Some(claim) = grant_claim {
            claim.commit();
        }
        Ok(VmmData::Empty)
    }

    fn replace_runtime_drive(
        &mut self,
        input: DriveConfigInput,
    ) -> Result<VmmData, VmmActionError> {
        let config = self.controller.prepare_runtime_drive_replacement(input)?;
        let DriveBackendConfig::File {
            path_on_host,
            is_read_only,
            ..
        } = config.backend()
        else {
            return Err(VmmActionError::DriveUpdate(
                DriveUpdateError::UnsupportedBackend,
            ));
        };
        let mut grant_claim: Option<PreparedDriveBackingClaim> = match &self.grant_authority {
            Some(authority) => authority
                .prepare_drive_backing_claim(
                    path_on_host,
                    grant_access_for_read_only(*is_read_only),
                )
                .map_err(|_| VmmActionError::ResourceGrant)?,
            None => None,
        };
        let backing_update = match grant_claim.as_mut() {
            Some(claim) => BlockBackingUpdate::Provided(
                claim
                    .take_backing(*is_read_only)
                    .map_err(|_| VmmActionError::ResourceGrant)?,
            ),
            None => BlockBackingUpdate::ConfiguredPath,
        };
        self.started_session
            .as_mut()
            .ok_or(VmmActionError::DriveUpdate(
                DriveUpdateError::ActiveSessionUnavailable,
            ))?
            .update_block_device(
                &config,
                backing_update,
                None,
                DriveLiveUpdateMode::Replacement,
            )
            .map_err(VmmActionError::DriveUpdate)?;
        self.controller.commit_drive_update(config)?;
        if let Some(claim) = grant_claim {
            claim.commit();
        }
        Ok(VmmData::Empty)
    }

    fn put_memory_hotplug(
        &mut self,
        input: bangbang_runtime::memory_hotplug::MemoryHotplugConfigInput,
    ) -> Result<VmmData, VmmActionError> {
        self.controller
            .handle_action(VmmAction::PutMemoryHotplug(input))
    }

    fn insert_runtime_drive(&mut self, input: DriveConfigInput) -> Result<VmmData, VmmActionError> {
        if !self.pci_enabled {
            return Err(VmmActionError::DriveRuntimeMutation(
                DriveRuntimeMutationError::PciNotEnabled,
            ));
        }
        let prepared_config = self.controller.prepare_runtime_drive_insert(input)?;
        let config = prepared_config.config().clone();
        match config.backend() {
            DriveBackendConfig::VhostUser { socket } => {
                self.started_session
                    .as_mut()
                    .ok_or(VmmActionError::DriveRuntimeMutation(
                        DriveRuntimeMutationError::ActiveSessionUnavailable,
                    ))?
                    .preflight_runtime_vhost_user_block_device(config.drive_id())
                    .map_err(VmmActionError::DriveRuntimeMutation)?;
                #[cfg(target_os = "macos")]
                let prepared_vhost_claim: Option<PreparedVhostUserSocketClaim> =
                    if self.grant_authority.is_some() {
                        self.vhost_user_broker_authority
                            .as_ref()
                            .ok_or(VmmActionError::ResourceGrant)?
                            .preflight()
                            .map_err(|_| VmmActionError::ResourceGrant)?;
                        Some(
                            self.directory_grant_authority
                                .as_ref()
                                .ok_or(VmmActionError::ResourceGrant)?
                                .prepare_vhost_user_socket(socket)
                                .map_err(|_| VmmActionError::ResourceGrant)?
                                .ok_or(VmmActionError::ResourceGrant)?,
                        )
                    } else {
                        None
                    };
                #[cfg(target_os = "macos")]
                let stream = match prepared_vhost_claim.as_ref() {
                    Some(claim) => self
                        .vhost_user_broker_authority
                        .as_ref()
                        .ok_or(VmmActionError::ResourceGrant)?
                        .connect(claim.grant_id(), claim.child())
                        .map_err(|source| {
                            VmmActionError::DriveRuntimeMutation(
                                DriveRuntimeMutationError::PrepareDevice {
                                    message: source.to_string(),
                                },
                            )
                        })?,
                    None => direct_vhost_user::connect(socket, DIRECT_VHOST_USER_OPERATION_TIMEOUT)
                        .map_err(|source| {
                            VmmActionError::DriveRuntimeMutation(
                                DriveRuntimeMutationError::PrepareDevice {
                                    message: source.to_string(),
                                },
                            )
                        })?,
                };
                #[cfg(not(target_os = "macos"))]
                let stream =
                    direct_vhost_user::connect(socket, DIRECT_VHOST_USER_OPERATION_TIMEOUT)
                        .map_err(|source| {
                            VmmActionError::DriveRuntimeMutation(
                                DriveRuntimeMutationError::PrepareDevice {
                                    message: source.to_string(),
                                },
                            )
                        })?;
                let frontend = PreparedVhostUserBlockFrontend::discover(
                    stream,
                    config.cache_type(),
                    DIRECT_VHOST_USER_OPERATION_TIMEOUT,
                )
                .map_err(|source| {
                    VmmActionError::DriveRuntimeMutation(DriveRuntimeMutationError::PrepareDevice {
                        message: source.to_string(),
                    })
                })?;
                #[cfg(target_os = "macos")]
                let drive_id = config.drive_id().to_string();
                self.started_session
                    .as_mut()
                    .ok_or(VmmActionError::DriveRuntimeMutation(
                        DriveRuntimeMutationError::ActiveSessionUnavailable,
                    ))?
                    .insert_runtime_block_device(RuntimeBlockDeviceResource::vhost_user(
                        config, frontend,
                    ))
                    .map_err(VmmActionError::DriveRuntimeMutation)?;
                #[cfg(target_os = "macos")]
                if let Some(claim) = prepared_vhost_claim {
                    let lease = claim.commit();
                    self.vhost_user_grant_states.insert(drive_id, lease);
                }
            }
            DriveBackendConfig::File {
                path_on_host,
                is_read_only,
                ..
            } => {
                let mut grant_claim: Option<PreparedDriveBackingClaim> = match &self.grant_authority
                {
                    Some(authority) => Some(
                        authority
                            .prepare_drive_backing_claim(
                                path_on_host,
                                grant_access_for_read_only(*is_read_only),
                            )
                            .map_err(|_| VmmActionError::ResourceGrant)?
                            .ok_or(VmmActionError::ResourceGrant)?,
                    ),
                    None => None,
                };
                let backing = match grant_claim.as_mut() {
                    Some(claim) => Some(
                        claim
                            .take_backing(*is_read_only)
                            .map_err(|_| VmmActionError::ResourceGrant)?,
                    ),
                    None => None,
                };
                // Backing open/stat work is completed on the API thread. The prepared
                // object crosses the run-loop command boundary with no ambient path use.
                let prepared_device = PreparedBlockDevice::from_config_with_backing(
                    &config, backing,
                )
                .map_err(|source| {
                    VmmActionError::DriveRuntimeMutation(DriveRuntimeMutationError::PrepareDevice {
                        message: source.to_string(),
                    })
                })?;
                let session = self.started_session.as_mut().ok_or({
                    VmmActionError::DriveRuntimeMutation(
                        DriveRuntimeMutationError::ActiveSessionUnavailable,
                    )
                })?;
                session
                    .insert_runtime_block_device(RuntimeBlockDeviceResource::prepared(
                        prepared_device,
                    ))
                    .map_err(VmmActionError::DriveRuntimeMutation)?;
                if let Some(claim) = grant_claim {
                    claim.commit();
                }
            }
        }
        self.controller.commit_runtime_drive_insert(prepared_config);
        Ok(VmmData::Empty)
    }

    fn remove_drive(&mut self, drive_id: &str) -> Result<VmmData, VmmActionError> {
        let state = self.controller.instance_info().state;
        if state == bangbang_runtime::InstanceState::NotStarted {
            return Err(VmmActionError::UnsupportedState {
                action: "HotUnplugDevice",
                state,
            });
        }
        if !self.pci_enabled {
            return Err(VmmActionError::DriveRuntimeMutation(
                DriveRuntimeMutationError::PciNotEnabled,
            ));
        }
        let prepared = self.controller.prepare_runtime_drive_removal(drive_id)?;
        let session = self.started_session.as_mut().ok_or({
            VmmActionError::DriveRuntimeMutation(
                DriveRuntimeMutationError::ActiveSessionUnavailable,
            )
        })?;
        session
            .remove_runtime_block_device(prepared.drive_id())
            .map_err(VmmActionError::DriveRuntimeMutation)?;
        self.drive_grant_states.remove(prepared.drive_id());
        #[cfg(target_os = "macos")]
        self.vhost_user_grant_states.remove(prepared.drive_id());
        self.controller.commit_runtime_drive_removal(prepared);
        Ok(VmmData::Empty)
    }

    fn put_network_interface(
        &mut self,
        input: NetworkInterfaceConfigInput,
    ) -> Result<VmmData, VmmActionError> {
        if self.controller.instance_info().state == bangbang_runtime::InstanceState::NotStarted {
            return self
                .controller
                .handle_action(VmmAction::PutNetworkInterface(input));
        }
        if !self.pci_enabled {
            return Err(VmmActionError::NetworkRuntimeMutation(
                NetworkRuntimeMutationError::PciNotEnabled,
            ));
        }
        let prepared = self
            .controller
            .prepare_runtime_network_interface_insert(input)?;
        let config = prepared.config().clone();
        let session = self.started_session.as_mut().ok_or({
            VmmActionError::NetworkRuntimeMutation(
                NetworkRuntimeMutationError::ActiveSessionUnavailable,
            )
        })?;
        session
            .insert_runtime_network_device(config, self.vmnet_authority)
            .map_err(VmmActionError::NetworkRuntimeMutation)?;
        self.controller
            .commit_runtime_network_interface_insert(prepared);
        Ok(VmmData::Empty)
    }

    fn remove_network_interface(&mut self, iface_id: &str) -> Result<VmmData, VmmActionError> {
        let state = self.controller.instance_info().state;
        if state == bangbang_runtime::InstanceState::NotStarted {
            return Err(VmmActionError::UnsupportedState {
                action: "HotUnplugDevice",
                state,
            });
        }
        if !self.pci_enabled {
            return Err(VmmActionError::NetworkRuntimeMutation(
                NetworkRuntimeMutationError::PciNotEnabled,
            ));
        }
        let prepared = self
            .controller
            .prepare_runtime_network_interface_removal(iface_id)?;
        let session = self.started_session.as_mut().ok_or({
            VmmActionError::NetworkRuntimeMutation(
                NetworkRuntimeMutationError::ActiveSessionUnavailable,
            )
        })?;
        session
            .remove_runtime_network_device(prepared.iface_id())
            .map_err(VmmActionError::NetworkRuntimeMutation)?;
        self.controller
            .commit_runtime_network_interface_removal(prepared);
        Ok(VmmData::Empty)
    }

    fn put_logger(&mut self, input: LoggerConfigInput) -> Result<VmmData, VmmActionError> {
        let config = self.controller.prepare_logger_config(input)?;
        let provided_file = match (&self.grant_authority, config.log_path()) {
            (Some(authority), Some(reference)) => authority
                .claim_file(reference, ResourceRole::LoggerSink, GrantAccess::WriteOnly)
                .map_err(|_| VmmActionError::ResourceGrant)?,
            _ => None,
        };
        let adopted = provided_file.is_some();
        let prepared = self
            .controller
            .prepare_logger_update(config, provided_file)
            .map_err(|error| match error {
                VmmActionError::LoggerConfig(_) if adopted => VmmActionError::ResourceGrant,
                error => error,
            })?;

        self.controller.commit_logger_config(prepared);
        Ok(VmmData::Empty)
    }

    fn put_metrics(&mut self, input: MetricsConfigInput) -> Result<VmmData, VmmActionError> {
        let config = self.controller.prepare_metrics_config(input)?;
        let provided_file = match &self.grant_authority {
            Some(authority) => authority
                .claim_file(
                    config.metrics_path(),
                    ResourceRole::MetricsSink,
                    GrantAccess::WriteOnly,
                )
                .map_err(|_| VmmActionError::ResourceGrant)?,
            None => None,
        };
        let adopted = provided_file.is_some();
        let prepared = self
            .controller
            .prepare_metrics_update(config, provided_file)
            .map_err(|error| match error {
                VmmActionError::MetricsConfig(_) if adopted => VmmActionError::ResourceGrant,
                error => error,
            })?;

        self.controller.commit_metrics_config(prepared);
        Ok(VmmData::Empty)
    }

    fn put_pmem(&mut self, input: PmemConfigInput) -> Result<VmmData, VmmActionError> {
        if self.controller.instance_info().state != bangbang_runtime::InstanceState::NotStarted {
            return self.insert_runtime_pmem(input);
        }
        let config = self.controller.prepare_pmem_config(input)?;
        let backing = match &self.grant_authority {
            Some(authority) => authority
                .claim_file(
                    std::path::Path::new(config.path_on_host()),
                    ResourceRole::PmemBacking,
                    grant_access_for_read_only(config.read_only()),
                )
                .map_err(|_| VmmActionError::ResourceGrant)?
                .map(|file| PmemFileBacking::from_file(file, config.read_only()))
                .transpose()
                .map_err(|_| VmmActionError::ResourceGrant)?,
            None => None,
        };
        let pmem_id = config.id().to_string();

        self.controller.commit_pmem_config(config);
        match backing {
            Some(backing) => {
                self.pmem_grant_states
                    .insert(pmem_id, BackingGrantState::Prepared(backing));
            }
            None => {
                self.pmem_grant_states.remove(&pmem_id);
            }
        }
        Ok(VmmData::Empty)
    }

    fn insert_runtime_pmem(&mut self, input: PmemConfigInput) -> Result<VmmData, VmmActionError> {
        if !self.pci_enabled {
            return Err(VmmActionError::PmemRuntimeMutation(
                PmemRuntimeMutationError::PciNotEnabled,
            ));
        }
        let prepared_config = self.controller.prepare_runtime_pmem_insert(input)?;
        let config = prepared_config.config();
        self.started_session
            .as_mut()
            .ok_or(VmmActionError::PmemRuntimeMutation(
                PmemRuntimeMutationError::ActiveSessionUnavailable,
            ))?
            .preflight_runtime_pmem_device(config)
            .map_err(VmmActionError::PmemRuntimeMutation)?;
        let mut grant_claim: Option<PreparedFileGrantClaim> = match &self.grant_authority {
            Some(authority) => Some(
                authority
                    .prepare_file_claim(
                        std::path::Path::new(config.path_on_host()),
                        ResourceRole::PmemBacking,
                        grant_access_for_read_only(config.read_only()),
                    )
                    .map_err(|_| VmmActionError::ResourceGrant)?
                    .ok_or(VmmActionError::ResourceGrant)?,
            ),
            None => None,
        };
        let backing = match grant_claim.as_mut() {
            Some(claim) => PmemFileBacking::from_file(
                claim
                    .take_file()
                    .map_err(|_| VmmActionError::ResourceGrant)?,
                config.read_only(),
            )
            .map_err(|_| VmmActionError::ResourceGrant)?,
            None => PmemFileBacking::open(config).map_err(|source| {
                VmmActionError::PmemRuntimeMutation(PmemRuntimeMutationError::PrepareDevice {
                    message: source.to_string(),
                })
            })?,
        };
        let config = config.clone();
        let session = self.started_session.as_mut().ok_or({
            VmmActionError::PmemRuntimeMutation(PmemRuntimeMutationError::ActiveSessionUnavailable)
        })?;
        session
            .insert_runtime_pmem_device(config, backing)
            .map_err(VmmActionError::PmemRuntimeMutation)?;
        if let Some(claim) = grant_claim {
            claim.commit();
        }
        self.controller.commit_runtime_pmem_insert(prepared_config);
        Ok(VmmData::Empty)
    }

    fn remove_pmem(&mut self, pmem_id: &str) -> Result<VmmData, VmmActionError> {
        let state = self.controller.instance_info().state;
        if state == bangbang_runtime::InstanceState::NotStarted {
            return Err(VmmActionError::UnsupportedState {
                action: "HotUnplugDevice",
                state,
            });
        }
        if !self.pci_enabled {
            return Err(VmmActionError::PmemRuntimeMutation(
                PmemRuntimeMutationError::PciNotEnabled,
            ));
        }
        let prepared = self.controller.prepare_runtime_pmem_removal(pmem_id)?;
        let session = self.started_session.as_mut().ok_or({
            VmmActionError::PmemRuntimeMutation(PmemRuntimeMutationError::ActiveSessionUnavailable)
        })?;
        session
            .remove_runtime_pmem_device(prepared.pmem_id())
            .map_err(VmmActionError::PmemRuntimeMutation)?;
        self.pmem_grant_states.remove(prepared.pmem_id());
        self.controller.commit_runtime_pmem_removal(prepared);
        Ok(VmmData::Empty)
    }

    fn put_serial(&mut self, input: SerialConfigInput) -> Result<VmmData, VmmActionError> {
        let config = self.controller.prepare_serial_config(input)?;
        let output = match (&self.grant_authority, config.serial_out_path()) {
            (Some(authority), Some(reference)) => authority
                .claim_file(reference, ResourceRole::SerialSink, GrantAccess::WriteOnly)
                .map_err(|_| VmmActionError::ResourceGrant)?
                .map(SerialOutputFile::from_file)
                .transpose()
                .map_err(|_| VmmActionError::ResourceGrant)?,
            _ => None,
        };
        let grant_state = match output {
            Some(output) => SerialGrantState::Prepared(output),
            None => SerialGrantState::PathBased,
        };

        self.controller.commit_serial_config(config);
        self.serial_grant_state = grant_state;
        Ok(VmmData::Empty)
    }

    fn put_vsock(&mut self, input: VsockConfigInput) -> Result<VmmData, VmmActionError> {
        let config = self.controller.prepare_vsock_config(input)?;
        #[cfg(target_os = "macos")]
        let grant_state = match &self.directory_grant_authority {
            Some(authority) => match authority
                .claim_socket_directory(config.uds_path(), ResourceRole::VsockSocketDirectory)
                .map_err(|_| VmmActionError::ResourceGrant)?
            {
                Some(claim) => VsockGrantState::Prepared(claim),
                None => VsockGrantState::PathBased,
            },
            None => VsockGrantState::PathBased,
        };

        self.controller.commit_vsock_config(config);
        #[cfg(target_os = "macos")]
        {
            self.vsock_grant_state = grant_state;
        }
        Ok(VmmData::Empty)
    }

    fn flush_metrics(&mut self) -> Result<VmmData, VmmActionError> {
        let diagnostics = self.metrics_diagnostics();

        self.controller.flush_metrics_with_diagnostics(&diagnostics)
    }

    fn pause_instance(&mut self) -> Result<VmmData, VmmActionError> {
        let transition = self.controller.preflight_pause_instance()?;
        let Some(session) = self.started_session.as_mut() else {
            return Err(VmmActionError::Lifecycle(BackendError::InvalidState(
                "active session unavailable",
            )));
        };

        if transition == VmStateTransition::AlreadyInTargetState {
            return Ok(VmmData::Empty);
        }
        session.pause().map_err(VmmActionError::Lifecycle)?;
        self.controller.pause_instance()
    }

    fn resume_instance(&mut self) -> Result<VmmData, VmmActionError> {
        let transition = self.controller.preflight_resume_instance()?;
        let Some(session) = self.started_session.as_mut() else {
            return Err(VmmActionError::Lifecycle(BackendError::InvalidState(
                "active session unavailable",
            )));
        };

        if transition == VmStateTransition::AlreadyInTargetState {
            return Ok(VmmData::Empty);
        }
        session.resume().map_err(VmmActionError::Lifecycle)?;
        self.controller.resume_instance()
    }

    fn create_snapshot(&mut self, input: SnapshotCreateInput) -> Result<VmmData, VmmActionError> {
        self.publish_native_v1_snapshot(&input)
            .map_err(native_v1_snapshot_publication_action_error)?;
        Ok(VmmData::Empty)
    }

    fn load_snapshot(&mut self, input: SnapshotLoadInput) -> Result<VmmData, VmmActionError> {
        if self.pci_enabled {
            return Err(VmmActionError::SnapshotUnsupported);
        }
        let resume_requested = self
            .restore_native_v1_snapshot(&input)
            .map_err(native_v1_snapshot_load_action_error)?;
        if resume_requested {
            self.resume_instance()
                .map_err(native_v1_snapshot_resume_action_error)?;
        }
        Ok(VmmData::Empty)
    }

    fn update_block_device(&mut self, input: DriveUpdateInput) -> Result<VmmData, VmmActionError> {
        if self.controller.instance_info().state == bangbang_runtime::InstanceState::NotStarted {
            return Err(VmmActionError::UnsupportedState {
                action: VmmAction::UpdateBlockDevice(input).name(),
                state: self.controller.instance_info().state,
            });
        }

        let refresh_backing = input.path_on_host().is_some();
        let rate_limiter_update = input.rate_limiter();
        let updated_config = self.controller.updated_drive_config(input)?;
        let mut grant_claim: Option<PreparedDriveBackingClaim> = None;
        match updated_config.backend() {
            DriveBackendConfig::VhostUser { .. } => {
                debug_assert!(!refresh_backing);
                debug_assert!(rate_limiter_update.is_none());
                let session = self
                    .started_session
                    .as_mut()
                    .ok_or(VmmActionError::DriveUpdate(
                        DriveUpdateError::ActiveSessionUnavailable,
                    ))?;
                session
                    .update_block_device(
                        &updated_config,
                        BlockBackingUpdate::Unchanged,
                        None,
                        DriveLiveUpdateMode::Patch,
                    )
                    .map_err(VmmActionError::DriveUpdate)?;
            }
            DriveBackendConfig::File {
                path_on_host,
                is_read_only,
                ..
            } if refresh_backing || rate_limiter_update.is_some() => {
                let session = self
                    .started_session
                    .as_mut()
                    .ok_or(VmmActionError::DriveUpdate(
                        DriveUpdateError::ActiveSessionUnavailable,
                    ))?;
                let backing_update = if refresh_backing {
                    match &self.grant_authority {
                        Some(authority) => {
                            grant_claim = authority
                                .prepare_drive_backing_claim(
                                    path_on_host,
                                    grant_access_for_read_only(*is_read_only),
                                )
                                .map_err(|_| VmmActionError::ResourceGrant)?;
                            match grant_claim.as_mut() {
                                Some(claim) => BlockBackingUpdate::Provided(
                                    claim
                                        .take_backing(*is_read_only)
                                        .map_err(|_| VmmActionError::ResourceGrant)?,
                                ),
                                None => BlockBackingUpdate::ConfiguredPath,
                            }
                        }
                        None => BlockBackingUpdate::ConfiguredPath,
                    }
                } else {
                    BlockBackingUpdate::Unchanged
                };
                session
                    .update_block_device(
                        &updated_config,
                        backing_update,
                        rate_limiter_update,
                        DriveLiveUpdateMode::Patch,
                    )
                    .map_err(VmmActionError::DriveUpdate)?;
            }
            DriveBackendConfig::File { .. } => {}
        }
        self.controller.commit_drive_update(updated_config)?;
        if let Some(claim) = grant_claim {
            claim.commit();
        }

        Ok(VmmData::Empty)
    }

    fn update_network_interface(
        &mut self,
        input: NetworkInterfaceUpdateInput,
    ) -> Result<VmmData, VmmActionError> {
        if self.controller.instance_info().state == bangbang_runtime::InstanceState::NotStarted {
            return Err(VmmActionError::UnsupportedState {
                action: VmmAction::UpdateNetworkInterface(input).name(),
                state: self.controller.instance_info().state,
            });
        }

        let (update, updated_config) = self.controller.prepare_network_interface_update(input)?;
        if !update.is_noop() {
            let Some(session) = self.started_session.as_mut() else {
                return Err(VmmActionError::NetworkInterfaceUpdate(
                    NetworkInterfaceUpdateError::ActiveSessionUnavailable,
                ));
            };

            session
                .update_network_interface(update)
                .map_err(VmmActionError::NetworkInterfaceUpdate)?;
        }
        self.controller
            .commit_network_interface_update(updated_config)?;

        Ok(VmmData::Empty)
    }

    fn update_pmem(&mut self, input: PmemUpdateInput) -> Result<VmmData, VmmActionError> {
        if self.controller.instance_info().state == bangbang_runtime::InstanceState::NotStarted {
            return Err(VmmActionError::UnsupportedState {
                action: VmmAction::PatchPmem(input).name(),
                state: self.controller.instance_info().state,
            });
        }

        let (update, updated_config) = self.controller.prepare_pmem_update(input)?;
        if !update.is_noop() {
            let Some(session) = self.started_session.as_mut() else {
                return Err(VmmActionError::PmemUpdate(
                    PmemUpdateError::ActiveSessionUnavailable,
                ));
            };

            session
                .update_pmem(update)
                .map_err(VmmActionError::PmemUpdate)?;
        }
        self.controller.commit_pmem_update(updated_config)?;

        Ok(VmmData::Empty)
    }

    fn update_balloon(&mut self, input: BalloonUpdateInput) -> Result<VmmData, VmmActionError> {
        let updated_config = self.controller.updated_balloon_config(input)?;
        let Some(session) = self.started_session.as_mut() else {
            return Err(VmmActionError::BalloonUpdate(
                BalloonUpdateError::ActiveSessionUnavailable,
            ));
        };

        session
            .update_balloon(updated_config)
            .map_err(VmmActionError::BalloonUpdate)?;
        self.controller.commit_balloon_update(updated_config);

        Ok(VmmData::Empty)
    }

    fn update_balloon_statistics(
        &mut self,
        input: BalloonStatsUpdateInput,
    ) -> Result<VmmData, VmmActionError> {
        let updated_config = self.controller.updated_balloon_stats_config(input)?;
        let Some(session) = self.started_session.as_mut() else {
            return Err(VmmActionError::BalloonUpdate(
                BalloonUpdateError::ActiveSessionUnavailable,
            ));
        };

        session
            .update_balloon_statistics(input)
            .map_err(VmmActionError::BalloonUpdate)?;
        self.controller.commit_balloon_update(updated_config);

        Ok(VmmData::Empty)
    }

    fn update_memory_hotplug(
        &mut self,
        input: MemoryHotplugSizeUpdateInput,
    ) -> Result<VmmData, VmmActionError> {
        let update = self.controller.memory_hotplug_size_update(input)?;
        let Some(session) = self.started_session.as_mut() else {
            return Err(VmmActionError::MemoryHotplugUpdate(
                MemoryHotplugUpdateError::ActiveSessionUnavailable,
            ));
        };

        session
            .update_memory_hotplug(update)
            .map_err(VmmActionError::MemoryHotplugUpdate)?;
        self.controller.commit_memory_hotplug_size_update(update);

        Ok(VmmData::Empty)
    }

    fn memory_hotplug_status(&mut self) -> Result<VmmData, VmmActionError> {
        if self.controller.instance_info().state == bangbang_runtime::InstanceState::NotStarted {
            return self.controller.handle_action(VmmAction::GetMemoryHotplug);
        }

        let config = self
            .controller
            .memory_hotplug_config()
            .ok_or(VmmActionError::MemoryHotplugUnsupported)?;
        let requested_size_mib = self
            .controller
            .memory_hotplug_status()
            .ok_or(VmmActionError::MemoryHotplugUnsupported)?
            .requested_size_mib();
        let Some(session) = self.started_session.as_mut() else {
            return Err(VmmActionError::MemoryHotplugStatus(
                MemoryHotplugStatusError::ActiveSessionUnavailable,
            ));
        };
        let status = session
            .memory_hotplug_status(config, requested_size_mib)
            .map_err(VmmActionError::MemoryHotplugStatus)?;

        Ok(VmmData::MemoryHotplugStatus(status))
    }

    fn balloon_stats(&mut self) -> Result<VmmData, VmmActionError> {
        if self.controller.instance_info().state == bangbang_runtime::InstanceState::NotStarted {
            return Err(VmmActionError::UnsupportedState {
                action: VmmAction::GetBalloonStats.name(),
                state: self.controller.instance_info().state,
            });
        }

        let config = self
            .controller
            .balloon_config()
            .ok_or(VmmActionError::BalloonUnsupported)?;
        let Some(session) = self.started_session.as_mut() else {
            return Err(VmmActionError::BalloonStats(
                BalloonStatsError::ActiveSessionUnavailable,
            ));
        };
        let stats = session
            .balloon_stats(config)
            .map_err(VmmActionError::BalloonStats)?;

        Ok(VmmData::BalloonStatistics(stats))
    }

    fn balloon_hinting_status(&mut self) -> Result<VmmData, VmmActionError> {
        if self.controller.instance_info().state == bangbang_runtime::InstanceState::NotStarted {
            return Err(VmmActionError::UnsupportedState {
                action: VmmAction::GetBalloonHintingStatus.name(),
                state: self.controller.instance_info().state,
            });
        }

        let config = self
            .controller
            .balloon_config()
            .ok_or(VmmActionError::BalloonUnsupported)?;
        if !config.free_page_hinting() {
            return Err(VmmActionError::BalloonUnsupported);
        }

        let Some(session) = self.started_session.as_mut() else {
            return Err(VmmActionError::BalloonHintingStatus(
                BalloonHintingStatusError::ActiveSessionUnavailable,
            ));
        };
        let status = session.balloon_hinting_status().map_err(|err| match err {
            BalloonHintingStatusError::HintingNotEnabled => VmmActionError::BalloonUnsupported,
            err => VmmActionError::BalloonHintingStatus(err),
        })?;

        Ok(VmmData::BalloonHintingStatus(status))
    }

    fn start_balloon_hinting(
        &mut self,
        input: BalloonHintingStartInput,
    ) -> Result<VmmData, VmmActionError> {
        self.with_active_hinting_session(VmmAction::PatchBalloonHintingStart(input), |session| {
            session.start_balloon_hinting(input)
        })?;

        Ok(VmmData::Empty)
    }

    fn stop_balloon_hinting(&mut self) -> Result<VmmData, VmmActionError> {
        self.with_active_hinting_session(VmmAction::PatchBalloonHintingStop, |session| {
            session.stop_balloon_hinting()
        })?;

        Ok(VmmData::Empty)
    }

    fn with_active_hinting_session(
        &mut self,
        action: VmmAction,
        command: impl FnOnce(&mut S::Session) -> Result<(), BalloonHintingCommandError>,
    ) -> Result<(), VmmActionError> {
        if self.controller.instance_info().state == bangbang_runtime::InstanceState::NotStarted {
            return Err(VmmActionError::UnsupportedState {
                action: action.name(),
                state: self.controller.instance_info().state,
            });
        }

        let config = self
            .controller
            .balloon_config()
            .ok_or(VmmActionError::BalloonUnsupported)?;
        if !config.free_page_hinting() {
            return Err(VmmActionError::BalloonUnsupported);
        }

        let Some(session) = self.started_session.as_mut() else {
            return Err(VmmActionError::BalloonHintingCommand(
                BalloonHintingCommandError::ActiveSessionUnavailable,
            ));
        };

        command(session).map_err(|err| match err {
            BalloonHintingCommandError::HintingNotEnabled => VmmActionError::BalloonUnsupported,
            err => VmmActionError::BalloonHintingCommand(err),
        })
    }

    fn flush_automatic_metrics(&mut self) -> Result<bool, VmmActionError> {
        let diagnostics = self.metrics_diagnostics();

        self.controller
            .flush_automatic_metrics_with_diagnostics(&diagnostics)
    }

    pub(crate) fn handle_initial_metrics_flush(&mut self) {
        if !self.has_started_session() || self.initial_metrics_attempted {
            return;
        }

        self.initial_metrics_attempted = true;
        let _ = self.flush_automatic_metrics();
    }

    fn handle_periodic_metrics_flush(&mut self) {
        let _ = self.flush_automatic_metrics();
    }

    pub(crate) fn handle_terminal_metrics_flush(&mut self) {
        self.handle_initial_metrics_flush();
        if !self.has_started_session() || self.terminal_metrics_attempted {
            return;
        }

        self.terminal_metrics_attempted = true;
        let _ = self.flush_automatic_metrics();
    }

    fn balloon_statistics_update_interval(&self) -> Option<Duration> {
        if self.controller.instance_info().state != bangbang_runtime::InstanceState::Running {
            return None;
        }

        let interval_s = self.controller.balloon_config()?.stats_polling_interval_s();
        if interval_s == 0 {
            return None;
        }

        Some(Duration::from_secs(u64::from(interval_s)))
    }

    fn trigger_periodic_balloon_statistics_update(&mut self) -> Result<bool, VmmActionError> {
        if self.balloon_statistics_update_interval().is_none() {
            return Ok(false);
        }

        let Some(session) = self.started_session.as_mut() else {
            return Err(VmmActionError::BalloonUpdate(
                BalloonUpdateError::ActiveSessionUnavailable,
            ));
        };

        session
            .trigger_balloon_statistics_update()
            .map_err(VmmActionError::BalloonUpdate)?;

        Ok(true)
    }

    fn metrics_diagnostics(&self) -> MetricsDiagnostics {
        let session_diagnostics = self
            .started_session
            .as_ref()
            .map(ProcessSessionDiagnostics::metrics_diagnostics)
            .unwrap_or_default();
        let signal_diagnostics = self
            .process_signal_metrics
            .as_ref()
            .map(|metrics| MetricsDiagnostics::new().with_signal_metrics(metrics.snapshot()))
            .unwrap_or_default();
        self.process_metrics_diagnostics
            .clone()
            .merged_with(signal_diagnostics)
            .merged_with(self.starter.metrics_diagnostics())
            .merged_with(session_diagnostics)
    }

    pub(crate) fn process_exit_wakeup_fd(&self) -> Option<RawFd> {
        self.started_session
            .as_ref()
            .and_then(ProcessSessionDiagnostics::process_exit_wakeup_fd)
    }

    pub(crate) fn drain_process_exit_wakeup(&mut self) -> Result<(), std::io::ErrorKind> {
        if let Some(session) = self.started_session.as_mut() {
            session.drain_process_exit_wakeup()?;
        }

        Ok(())
    }

    pub(crate) fn process_exit_status(&self) -> ProcessSessionExitStatus {
        if self.terminal_snapshot_load_failure || self.terminal_instance_start_failure {
            return ProcessSessionExitStatus::Terminal;
        }
        self.started_session
            .as_ref()
            .map(ProcessSessionDiagnostics::process_exit_status)
            .unwrap_or_default()
    }
}

impl<S> ProcessVmm<S>
where
    S: InstanceStartExecutor,
{
    #[cfg(target_os = "macos")]
    fn prepare_snapshot_vsock_restore(
        &self,
        captured: Option<&VsockBackendSelector>,
        input: &SnapshotLoadInput,
    ) -> Result<Option<PreparedVsockRestoreResource>, NativeV1SnapshotLoadError> {
        prepare_vsock_restore_resource(
            captured,
            input.vsock_override(),
            self.directory_grant_authority.as_ref(),
            self.socket_broker_authority.as_ref(),
            self.socket_namespace.as_ref(),
            || self.snapshot_capture_cancellation.is_cancelled(),
        )
        .map_err(NativeV1SnapshotLoadError::VsockResource)
    }

    #[cfg(target_os = "macos")]
    fn prepare_contained_snapshot_v1_load(
        &self,
        input: &SnapshotLoadInput,
    ) -> Result<Option<PreparedHvfSnapshotV1Load>, NativeV1SnapshotLoadError> {
        let Some(authority) = &self.grant_authority else {
            return Ok(None);
        };
        let state_path = input.snapshot_path();
        let memory_path = input.mem_backend().backend_path();
        let state_id = grant_reference_id(Path::new(state_path))
            .map_err(NativeV1SnapshotLoadError::Resource)?;
        let memory_id = grant_reference_id(Path::new(memory_path))
            .map_err(NativeV1SnapshotLoadError::Resource)?;

        let mut inspection_requests = Vec::with_capacity(2);
        if let Some(id) = &state_id {
            inspection_requests.push((
                id.clone(),
                ResourceRole::SnapshotStateInput,
                GrantAccess::ReadOnly,
            ));
        }
        if let Some(id) = &memory_id {
            inspection_requests.push((
                id.clone(),
                ResourceRole::SnapshotMemoryInput,
                GrantAccess::ReadOnly,
            ));
        }
        let inspected = authority
            .duplicate_exact_files(&inspection_requests)
            .map_err(NativeV1SnapshotLoadError::Resource)?;
        let mut inspected = inspected.into_iter();
        let state_file = state_id
            .as_ref()
            .map(|_| inspected.next().ok_or(GrantClaimError))
            .transpose()
            .map_err(NativeV1SnapshotLoadError::Resource)?;
        if memory_id.is_some() {
            drop(
                inspected
                    .next()
                    .ok_or(NativeV1SnapshotLoadError::Resource(GrantClaimError))?,
            );
        }
        debug_assert!(inspected.next().is_none());

        let state = match state_file {
            Some(file) => prepare_snapshot_state_file(file),
            None => prepare_snapshot_state_path(Path::new(state_path)),
        }
        .map_err(NativeV1SnapshotLoadError::Artifact)?;
        let state = PreparedHvfSnapshotV1State::from_prepared_state(state)
            .map_err(NativeV1SnapshotLoadError::Prepare)?;
        let mut root_claim = authority
            .prepare_drive_backing_claim(state.root_backing_path(), GrantAccess::ReadOnly)
            .map_err(NativeV1SnapshotLoadError::Resource)?;
        let root = root_claim
            .as_mut()
            .map(PreparedDriveBackingClaim::take_snapshot_read_only_file)
            .transpose()
            .map_err(NativeV1SnapshotLoadError::Resource)?;

        let mut requests = Vec::with_capacity(2);
        if let Some(id) = &state_id {
            requests.push((
                id.clone(),
                ResourceRole::SnapshotStateInput,
                GrantAccess::ReadOnly,
            ));
        }
        if let Some(id) = &memory_id {
            requests.push((
                id.clone(),
                ResourceRole::SnapshotMemoryInput,
                GrantAccess::ReadOnly,
            ));
        }
        let claimed = authority
            .take_exact_files(&requests)
            .map_err(NativeV1SnapshotLoadError::Resource)?;
        let mut claimed = claimed.into_iter();
        if state_id.is_some() {
            drop(
                claimed
                    .next()
                    .ok_or(NativeV1SnapshotLoadError::Resource(GrantClaimError))?,
            );
        }
        let memory = memory_id
            .as_ref()
            .map(|_| claimed.next().ok_or(GrantClaimError))
            .transpose()
            .map_err(NativeV1SnapshotLoadError::Resource)?;
        debug_assert!(claimed.next().is_none());

        let prepared = match memory {
            Some(file) => state.load_memory_file(file),
            None => state.load_memory_path(Path::new(memory_path)),
        }
        .map_err(NativeV1SnapshotLoadError::Artifact)?;
        let prepared = prepared
            .finish(root, Instant::now())
            .map_err(NativeV1SnapshotLoadError::Prepare)?;
        if let Some(claim) = root_claim {
            claim.commit();
        }
        Ok(Some(prepared))
    }

    #[cfg(not(target_os = "macos"))]
    fn prepare_contained_snapshot_v1_load(
        &self,
        _input: &SnapshotLoadInput,
    ) -> Result<Option<PreparedHvfSnapshotV1Load>, NativeV1SnapshotLoadError> {
        Ok(None)
    }

    /// Restores one admitted native-v1 pair and commits the session paused.
    pub(crate) fn restore_native_v1_snapshot(
        &mut self,
        input: &SnapshotLoadInput,
    ) -> Result<bool, NativeV1SnapshotLoadError> {
        if self.terminal_snapshot_load_failure {
            return Err(NativeV1SnapshotLoadError::ProcessTerminal);
        }
        self.controller
            .preflight_load_snapshot(input)
            .map_err(NativeV1SnapshotLoadError::Preflight)?;

        #[cfg(target_os = "macos")]
        if let Some(unintegrated) = self.prepare_snapshot_vsock_restore(None, input)? {
            // Native-v1 artifacts do not encode vsock yet. Keep the public
            // gate fail-closed while exercising the exact #1490 handoff.
            let _ = unintegrated
                .abort()
                .map_err(NativeV1SnapshotLoadError::VsockResource)?;
            return Err(NativeV1SnapshotLoadError::ProcessTerminal);
        }

        let prepared = self.prepare_contained_snapshot_v1_load(input)?;
        let result = match prepared {
            Some(prepared) => self.starter.load_prepared_snapshot_v1(
                &self.controller,
                self.vmnet_authority,
                input,
                prepared,
            ),
            None => self
                .starter
                .load_snapshot_v1(&self.controller, self.vmnet_authority, input),
        };
        let restored = match result {
            Ok(restored) => restored,
            Err(error) => {
                if error.disposition() == HvfSnapshotV1RestoreDisposition::Terminal {
                    self.terminal_snapshot_load_failure = true;
                }
                return Err(error);
            }
        };
        let (session, controller_commit) = restored.into_parts();
        self.started_session = Some(session);
        Ok(self.controller.commit_snapshot_v1_load(controller_commit))
    }
}

impl<S> ProcessVmm<S>
where
    S: InstanceStartExecutor,
{
    #[cfg(target_os = "macos")]
    fn prepare_contained_snapshot_v1_outputs(
        &self,
        input: &SnapshotCreateInput,
    ) -> Result<Option<SnapshotArtifactOutputs>, NativeV1SnapshotPublicationError> {
        let Some(authority) = &self.directory_grant_authority else {
            return Ok(None);
        };
        let claims = authority
            .claim_snapshot_outputs(
                Path::new(input.snapshot_path()),
                Path::new(input.mem_file_path()),
            )
            .map_err(NativeV1SnapshotPublicationError::Resource)?;
        if claims.state.is_none() && claims.memory.is_none() {
            return Ok(None);
        }
        let namespace = self
            .socket_namespace
            .as_ref()
            .ok_or(NativeV1SnapshotPublicationError::Resource(GrantClaimError))?
            .try_clone()
            .map_err(|_| NativeV1SnapshotPublicationError::Resource(GrantClaimError))?;
        let tracker: Arc<dyn SnapshotStagingTracker> =
            Arc::new(SnapshotStagingRecordTracker::new(namespace));
        let state = match claims.state {
            Some(claim) => claim
                .artifact_output(Arc::clone(&tracker))
                .map_err(NativeV1SnapshotPublicationError::Resource)?,
            None => SnapshotArtifactOutput::path(input.snapshot_path()),
        };
        let memory = match claims.memory {
            Some(claim) => claim
                .artifact_output(Arc::clone(&tracker))
                .map_err(NativeV1SnapshotPublicationError::Resource)?,
            None => SnapshotArtifactOutput::path(input.mem_file_path()),
        };
        Ok(Some(SnapshotArtifactOutputs::new(state, memory)))
    }

    #[cfg(not(target_os = "macos"))]
    fn prepare_contained_snapshot_v1_outputs(
        &self,
        _input: &SnapshotCreateInput,
    ) -> Result<Option<SnapshotArtifactOutputs>, NativeV1SnapshotPublicationError> {
        Ok(None)
    }

    /// Publishes one admitted paused source as a native-v1 composite pair.
    pub(crate) fn publish_native_v1_snapshot(
        &mut self,
        input: &SnapshotCreateInput,
    ) -> Result<SnapshotCommitDurability, NativeV1SnapshotPublicationError> {
        self.controller
            .preflight_create_snapshot_request(input)
            .map_err(NativeV1SnapshotPublicationError::Preflight)?;

        let storage_configs = CaptureReadyStorageConfigs::new(
            self.controller.drive_configs().to_vec(),
            self.controller.pmem_configs().to_vec(),
        );
        let cancellation = self.snapshot_capture_cancellation.clone();
        let session = self
            .started_session
            .as_mut()
            .ok_or(NativeV1SnapshotPublicationError::SessionUnavailable)?;
        self.starter
            .preflight_snapshot_v1_storage(session, storage_configs, cancellation.clone())
            .map_err(NativeV1SnapshotPublicationError::StoragePreflight)?;
        let balloon_config = self.controller.balloon_config();
        self.starter
            .preflight_snapshot_v1_balloon(session, balloon_config)
            .map_err(NativeV1SnapshotPublicationError::BalloonPreflight)?;
        let memory_hotplug_config = self.controller.memory_hotplug_config();
        self.starter
            .preflight_snapshot_v1_memory_hotplug(session, memory_hotplug_config)
            .map_err(NativeV1SnapshotPublicationError::MemoryHotplugPreflight)?;
        let entropy_config = self.controller.entropy_config();
        self.starter
            .preflight_snapshot_v1_entropy(session, entropy_config)
            .map_err(NativeV1SnapshotPublicationError::EntropyPreflight)?;
        let serial_config = self.controller.serial_config().clone();
        self.starter
            .preflight_snapshot_v1_serial(session, serial_config.clone())
            .map_err(NativeV1SnapshotPublicationError::SerialPreflight)?;
        let network_configs = self.controller.network_interface_configs().to_vec();
        let mmds_config = self.controller.mmds_config().map_err(|source| {
            NativeV1SnapshotPublicationError::NetworkPreflight(
                ProcessCaptureReadyNetworkError::MmdsState { source },
            )
        })?;
        let mmds_state = self.controller.mmds_state_handle();
        self.starter
            .preflight_snapshot_v1_network(
                session,
                self.vmnet_authority,
                network_configs,
                mmds_config,
                mmds_state,
            )
            .map_err(NativeV1SnapshotPublicationError::NetworkPreflight)?;
        let vsock_config = self.controller.vsock_config().cloned();
        self.starter
            .preflight_snapshot_v1_vsock(session, vsock_config, cancellation.clone())
            .map_err(NativeV1SnapshotPublicationError::VsockPreflight)?;

        self.controller
            .preflight_create_snapshot_profile()
            .map_err(NativeV1SnapshotPublicationError::Preflight)?;
        if self.pci_enabled {
            return Err(NativeV1SnapshotPublicationError::Preflight(
                VmmActionError::SnapshotUnsupported,
            ));
        }

        let drive_config = match self.controller.drive_configs() {
            [drive_config] => drive_config.clone(),
            _ => return Err(NativeV1SnapshotPublicationError::ConfigurationUnavailable),
        };
        let paths = SnapshotArtifactPaths::new(input.snapshot_path(), input.mem_file_path());
        if self.started_session.is_none() {
            return Err(NativeV1SnapshotPublicationError::SessionUnavailable);
        }
        let outputs = self.prepare_contained_snapshot_v1_outputs(input)?;
        let session = self
            .started_session
            .as_mut()
            .ok_or(NativeV1SnapshotPublicationError::SessionUnavailable)?;

        let outcome = match outputs {
            Some(outputs) => self.starter.publish_snapshot_v1_to(
                session,
                &drive_config,
                &serial_config,
                outputs,
                cancellation,
            )?,
            None => self.starter.publish_snapshot_v1(
                session,
                &drive_config,
                &serial_config,
                &paths,
                cancellation,
            )?,
        };
        debug_assert_eq!(
            self.controller.instance_info().state,
            bangbang_runtime::InstanceState::Paused
        );
        Ok(outcome.durability())
    }
}

