impl ProcessNetworkPacketIoRegistry<SystemVmnetInterfaceBackend> {
    fn from_controller(
        controller: &VmmController,
        owner: ProcessVmnetAuthority,
    ) -> Result<(Self, Option<SharedMmdsMetrics>), ProcessNetworkPacketIoProviderBuildError> {
        validate_process_vmnet_authority(controller, owner).map_err(|error| match error {
            ProcessVmnetAuthorityValidationError::Provider(source) => source,
            ProcessVmnetAuthorityValidationError::HostNetworkNotAuthorized => {
                ProcessNetworkPacketIoProviderBuildError::AuthorityMismatch
            }
        })?;
        let mmds_config = controller
            .mmds_config()
            .map_err(|source| ProcessNetworkPacketIoProviderBuildError::MmdsState { source })?;
        let mmds_metrics = mmds_config.as_ref().map(|_| SharedMmdsMetrics::default());
        let mmds_detour =
            mmds_config
                .as_ref()
                .zip(mmds_metrics.as_ref())
                .map(|(config, metrics)| {
                    ProcessMmdsPacketDetourConfig::from_mmds_config(
                        controller.mmds_state_handle(),
                        config,
                        metrics.clone(),
                    )
                });

        let provider = Self::from_network_configs_and_mmds_detour_with_owner(
            controller.network_interface_configs(),
            mmds_detour.as_ref(),
            owner,
        )?;
        Ok((provider, mmds_metrics))
    }

    #[cfg(test)]
    fn from_network_configs(
        configs: &[NetworkInterfaceConfig],
    ) -> Result<Self, ProcessNetworkPacketIoProviderBuildError> {
        Self::from_network_configs_and_mmds_detour(configs, None)
    }

    #[cfg(test)]
    fn from_network_configs_and_mmds_detour(
        configs: &[NetworkInterfaceConfig],
        mmds_detour: Option<&ProcessMmdsPacketDetourConfig>,
    ) -> Result<Self, ProcessNetworkPacketIoProviderBuildError> {
        Self::from_network_configs_and_mmds_detour_with_owner(
            configs,
            mmds_detour,
            ProcessVmnetAuthority::Direct,
        )
    }

    fn from_network_configs_and_mmds_detour_with_owner(
        configs: &[NetworkInterfaceConfig],
        mmds_detour: Option<&ProcessMmdsPacketDetourConfig>,
        owner: ProcessVmnetAuthority,
    ) -> Result<Self, ProcessNetworkPacketIoProviderBuildError> {
        let mut factory = SystemProcessVmnetPacketIoBackendFactory;
        Self::from_network_configs_and_mmds_detour_with_factory_and_owner(
            configs,
            mmds_detour,
            owner,
            &mut factory,
        )
    }

    fn prepare_runtime_entry(
        &mut self,
        config: &NetworkInterfaceConfig,
        authority: ProcessVmnetAuthority,
    ) -> Result<
        PreparedProcessNetworkPacketIoEntry<SystemVmnetInterfaceBackend>,
        NetworkRuntimeMutationError,
    > {
        let mut factory = SystemProcessVmnetPacketIoBackendFactory;
        self.prepare_runtime_entry_with_factory(config, authority, &mut factory)
    }
}

fn runtime_network_packet_io_preparation_error(
    source: ProcessNetworkPacketIoProviderBuildError,
) -> NetworkRuntimeMutationError {
    let terminal = source.is_terminal();
    let unauthorized = matches!(
        source,
        ProcessNetworkPacketIoProviderBuildError::AuthorityMismatch
    );
    let message = match source {
        ProcessNetworkPacketIoProviderBuildError::AuthorityMismatch => {
            "network packet-I/O lifecycle owner is inconsistent"
        }
        ProcessNetworkPacketIoProviderBuildError::NetworkInterfaceCount { .. } => {
            "network interface count is unsupported"
        }
        ProcessNetworkPacketIoProviderBuildError::DuplicateInterface => {
            "network packet-I/O identity is already registered"
        }
        ProcessNetworkPacketIoProviderBuildError::DuplicateRealizedMac => {
            "network guest identity is already in use"
        }
        ProcessNetworkPacketIoProviderBuildError::ProviderCapacity { .. }
        | ProcessNetworkPacketIoProviderBuildError::RegistryCapacity => {
            "network packet-I/O capacity is exhausted"
        }
        ProcessNetworkPacketIoProviderBuildError::GenerationExhausted => {
            "network packet-I/O ownership generation is exhausted"
        }
        ProcessNetworkPacketIoProviderBuildError::MmdsState { .. } => "MMDS state is unavailable",
        ProcessNetworkPacketIoProviderBuildError::HostDeviceName { .. } => {
            "network host device configuration is unsupported"
        }
        ProcessNetworkPacketIoProviderBuildError::Start { .. } => "vmnet interface start failed",
        ProcessNetworkPacketIoProviderBuildError::PacketIoBuild { .. } => {
            "vmnet packet-I/O initialization failed"
        }
        ProcessNetworkPacketIoProviderBuildError::ReadinessBridge { .. } => {
            "vmnet packet readiness initialization failed"
        }
        ProcessNetworkPacketIoProviderBuildError::PacketEvents { .. } => {
            "vmnet packet event initialization failed"
        }
        ProcessNetworkPacketIoProviderBuildError::CleanupUncertain => {
            "vmnet cleanup could not be confirmed"
        }
        ProcessNetworkPacketIoProviderBuildError::MmdsNetworkStack { .. }
        | ProcessNetworkPacketIoProviderBuildError::MmdsOnlyPacketIoBuild { .. }
        | ProcessNetworkPacketIoProviderBuildError::MissingMmdsDetour => {
            "MMDS packet-I/O initialization failed"
        }
    };
    if unauthorized {
        return NetworkRuntimeMutationError::HostNetworkNotAuthorized;
    }
    if terminal {
        NetworkRuntimeMutationError::TerminalInsertion {
            message: message.to_string(),
        }
    } else {
        NetworkRuntimeMutationError::PreparePacketIo {
            message: message.to_string(),
        }
    }
}

impl<B> ProcessNetworkPacketIoRegistry<B>
where
    B: ProcessVmnetBackend,
{
    fn prepare_runtime_entry_with_factory<F>(
        &mut self,
        config: &NetworkInterfaceConfig,
        authority: ProcessVmnetAuthority,
        factory: &mut F,
    ) -> Result<PreparedProcessNetworkPacketIoEntry<B>, NetworkRuntimeMutationError>
    where
        F: ProcessVmnetPacketIoBackendFactory<Backend = B>,
    {
        if authority != self.owner {
            return Err(NetworkRuntimeMutationError::HostNetworkNotAuthorized);
        }
        let class = self.class_for_interface(config.iface_id());
        let vmnet_config = VmnetInterfaceConfig::from_host_dev_name(config.host_dev_name())
            .map(|vmnet| {
                vmnet
                    .with_guest_mac(config.guest_mac())
                    .with_mtu(config.mtu())
            })
            .map_err(|_| NetworkRuntimeMutationError::PreparePacketIo {
                message: "network host device configuration is unsupported".to_string(),
            })?;
        self.validate_runtime_authority(class, &vmnet_config, authority)?;
        self.prepare_entry_with_factory(config, class, false, factory)
            .map_err(runtime_network_packet_io_preparation_error)
    }

    #[cfg(test)]
    fn from_network_configs_and_mmds_detour_with_factory<F>(
        configs: &[NetworkInterfaceConfig],
        mmds_detour: Option<&ProcessMmdsPacketDetourConfig>,
        factory: &mut F,
    ) -> Result<Self, ProcessNetworkPacketIoProviderBuildError>
    where
        F: ProcessVmnetPacketIoBackendFactory<Backend = B>,
    {
        Self::from_network_configs_and_mmds_detour_with_factory_and_owner(
            configs,
            mmds_detour,
            ProcessVmnetAuthority::Direct,
            factory,
        )
    }

    fn from_network_configs_and_mmds_detour_with_factory_and_owner<F>(
        configs: &[NetworkInterfaceConfig],
        mmds_detour: Option<&ProcessMmdsPacketDetourConfig>,
        owner: ProcessVmnetAuthority,
        factory: &mut F,
    ) -> Result<Self, ProcessNetworkPacketIoProviderBuildError>
    where
        F: ProcessVmnetPacketIoBackendFactory<Backend = B>,
    {
        validate_network_interface_count(configs.len()).map_err(|source| {
            ProcessNetworkPacketIoProviderBuildError::NetworkInterfaceCount { source }
        })?;
        let startup_policy = if configs.is_empty()
            || mmds_detour.is_some_and(|detour| detour.covers_all_interfaces(configs))
        {
            ProcessNetworkPacketIoStartupPolicy::MmdsPreferred
        } else {
            ProcessNetworkPacketIoStartupPolicy::Vmnet
        };
        validate_process_vmnet_authority_for_configs(
            configs,
            startup_policy == ProcessNetworkPacketIoStartupPolicy::MmdsPreferred,
            owner,
        )
        .map_err(|error| match error {
            ProcessVmnetAuthorityValidationError::Provider(source) => source,
            ProcessVmnetAuthorityValidationError::HostNetworkNotAuthorized => {
                ProcessNetworkPacketIoProviderBuildError::AuthorityMismatch
            }
        })?;
        let mut entries = Vec::new();
        entries
            .try_reserve_exact(bangbang_runtime::network::MAX_NETWORK_INTERFACE_COUNT)
            .map_err(
                |source| ProcessNetworkPacketIoProviderBuildError::ProviderCapacity { source },
            )?;
        let mut reserved_macs = Vec::new();
        reserved_macs
            .try_reserve_exact(bangbang_runtime::network::MAX_NETWORK_INTERFACE_COUNT)
            .map_err(
                |source| ProcessNetworkPacketIoProviderBuildError::ProviderCapacity { source },
            )?;
        for config in configs {
            if let Some(mac) = config.guest_mac() {
                if reserved_macs.contains(&mac) {
                    return Err(ProcessNetworkPacketIoProviderBuildError::DuplicateRealizedMac);
                }
                reserved_macs.push(mac);
            }
        }
        let (readiness_signal, readiness_receiver) = mpsc::sync_channel(1);
        let mut provider = Self {
            owner,
            entries,
            reserved_macs,
            next_generation: 0,
            startup_policy,
            mmds_detour: mmds_detour.cloned(),
            readiness_signal,
            readiness_receiver: Some(readiness_receiver),
            readiness_wake: None,
            readiness_bridge: None,
        };
        for config in configs {
            let class = provider.class_for_interface(config.iface_id());
            let prepared = match provider.prepare_entry_with_factory(
                config,
                class,
                config.guest_mac().is_some(),
                factory,
            ) {
                Ok(prepared) => prepared,
                Err(source) => {
                    return Err(provider.cleanup_after_build_error(source));
                }
            };
            provider.publish_prepared(prepared);
        }
        Ok(provider)
    }

    fn class_for_interface(&self, iface_id: &str) -> ProcessNetworkPacketIoEntryClass {
        if self.startup_policy == ProcessNetworkPacketIoStartupPolicy::MmdsPreferred
            && self
                .mmds_detour
                .as_ref()
                .is_some_and(|detour| detour.interface_is_configured(iface_id))
        {
            ProcessNetworkPacketIoEntryClass::MmdsOnly
        } else {
            ProcessNetworkPacketIoEntryClass::Vmnet
        }
    }

    fn validate_runtime_authority(
        &self,
        class: ProcessNetworkPacketIoEntryClass,
        vmnet: &VmnetInterfaceConfig,
        authority: ProcessVmnetAuthority,
    ) -> Result<(), NetworkRuntimeMutationError> {
        if authority != self.owner {
            return Err(NetworkRuntimeMutationError::HostNetworkNotAuthorized);
        }
        if class == ProcessNetworkPacketIoEntryClass::MmdsOnly
            || matches!(authority, ProcessVmnetAuthority::Direct)
        {
            return Ok(());
        }
        let authority = authority
            .contained_authority()
            .ok_or(NetworkRuntimeMutationError::HostNetworkNotAuthorized)?;
        let max_interfaces = authority
            .max_interfaces()
            .ok_or(NetworkRuntimeMutationError::HostNetworkNotAuthorized)?;
        if self.vmnet_count() >= usize::from(max_interfaces) {
            return Err(NetworkRuntimeMutationError::HostNetworkNotAuthorized);
        }
        if !vmnet_authority_allows(authority, vmnet) {
            return Err(NetworkRuntimeMutationError::HostNetworkNotAuthorized);
        }
        Ok(())
    }

    fn prepare_entry_with_factory<F>(
        &mut self,
        config: &NetworkInterfaceConfig,
        class: ProcessNetworkPacketIoEntryClass,
        explicit_mac_pre_reserved: bool,
        factory: &mut F,
    ) -> Result<PreparedProcessNetworkPacketIoEntry<B>, ProcessNetworkPacketIoProviderBuildError>
    where
        F: ProcessVmnetPacketIoBackendFactory<Backend = B>,
    {
        if self
            .entries
            .iter()
            .any(|entry| entry.iface_id == config.iface_id())
        {
            return Err(ProcessNetworkPacketIoProviderBuildError::DuplicateInterface);
        }
        if self.entries.len() == bangbang_runtime::network::MAX_NETWORK_INTERFACE_COUNT {
            return Err(ProcessNetworkPacketIoProviderBuildError::RegistryCapacity);
        }
        if !explicit_mac_pre_reserved
            && config
                .guest_mac()
                .is_some_and(|mac| self.reserved_macs.contains(&mac))
        {
            return Err(ProcessNetworkPacketIoProviderBuildError::DuplicateRealizedMac);
        }
        let next_generation = self
            .next_generation
            .checked_add(1)
            .ok_or(ProcessNetworkPacketIoProviderBuildError::GenerationExhausted)?;
        let generation = self.next_generation;
        let iface_id = config.iface_id();
        let (packet_io, device_profile, backend_parameters, reserve_realized_mac) = match class {
            ProcessNetworkPacketIoEntryClass::MmdsOnly => {
                VmnetInterfaceConfig::from_host_dev_name(config.host_dev_name()).map_err(
                    |source| ProcessNetworkPacketIoProviderBuildError::HostDeviceName { source },
                )?;
                let Some(detour) =
                    self.mmds_detour
                        .as_ref()
                        .map(|detour| detour.detour_for_interface(iface_id))
                        .transpose()
                        .map_err(|source| {
                            ProcessNetworkPacketIoProviderBuildError::MmdsNetworkStack { source }
                        })?
                        .flatten()
                else {
                    return Err(ProcessNetworkPacketIoProviderBuildError::MissingMmdsDetour);
                };
                let packet_io =
                    MmdsOnlyVirtioNetworkPacketIo::with_guest_mac(detour, config.guest_mac())
                        .map_err(|source| {
                            ProcessNetworkPacketIoProviderBuildError::MmdsOnlyPacketIoBuild {
                                source,
                            }
                        })?;
                let device_profile = NetworkDeviceProfile::from_config(config);
                (
                    ProcessNetworkPacketIo::MmdsOnly(Box::new(packet_io)),
                    device_profile,
                    None,
                    !explicit_mac_pre_reserved && device_profile.guest_mac().is_some(),
                )
            }
            ProcessNetworkPacketIoEntryClass::Vmnet => {
                let (readiness_lease, packet_callback) =
                    VmnetPacketReadinessLease::new(generation, self.readiness_signal.clone());
                let vmnet_config =
                    VmnetInterfaceConfig::from_host_dev_name(config.host_dev_name())
                        .map(|vmnet| {
                            vmnet
                                .with_guest_mac(config.guest_mac())
                                .with_mtu(config.mtu())
                        })
                        .map_err(|source| {
                            ProcessNetworkPacketIoProviderBuildError::HostDeviceName { source }
                        })?;
                let prepared_rx =
                    PreparedVmnetVirtioNetworkRxBuffer::supported_maximum().map_err(|source| {
                        ProcessNetworkPacketIoProviderBuildError::PacketIoBuild { source }
                    })?;
                let detour =
                    self.mmds_detour
                        .as_ref()
                        .map(|detour| detour.detour_for_interface(iface_id))
                        .transpose()
                        .map_err(|source| {
                            ProcessNetworkPacketIoProviderBuildError::MmdsNetworkStack { source }
                        })?
                        .flatten();
                let backend = factory.new_backend(iface_id);
                let (mut backend, interface) =
                    StartedVmnetPacketIoBackend::start(backend, &vmnet_config).map_err(
                        |source| ProcessNetworkPacketIoProviderBuildError::Start { source },
                    )?;
                let parameters = backend.parameters().clone();
                let realized_mac = parameters.realized_mac();
                if !explicit_mac_pre_reserved && self.reserved_macs.contains(&realized_mac) {
                    return match backend.stop() {
                        Ok(()) => {
                            Err(ProcessNetworkPacketIoProviderBuildError::DuplicateRealizedMac)
                        }
                        Err(_) => Err(ProcessNetworkPacketIoProviderBuildError::CleanupUncertain),
                    };
                }
                let packet_envelope = if parameters.direct_virtio_header_enabled() {
                    VirtioNetworkPacketEnvelope::DirectVirtioHeader
                } else {
                    VirtioNetworkPacketEnvelope::RawEthernet
                };
                let rx_buffer_len = parameters.packet_buffer_size().ok_or(
                    ProcessNetworkPacketIoProviderBuildError::PacketIoBuild {
                        source: VmnetVirtioNetworkPacketIoBuildError::RxBufferTooSmall,
                    },
                )?;
                let read_batch_size = usize::from(parameters.read_max_packets().unwrap_or(1));
                let write_batch_size = usize::from(parameters.write_max_packets().unwrap_or(1));
                let mut packet_io =
                    VmnetVirtioNetworkPacketIo::with_prepared_batch_envelope_and_mmds_detour(
                        backend,
                        interface,
                        prepared_rx,
                        VmnetVirtioNetworkPacketProfile::new(
                            VmnetVirtioNetworkBatchLimits::new(
                                rx_buffer_len,
                                read_batch_size,
                                write_batch_size,
                            ),
                            packet_envelope,
                            Some(realized_mac),
                        ),
                        detour,
                        Some(readiness_lease),
                    )
                    .map_err(|source| {
                        ProcessNetworkPacketIoProviderBuildError::PacketIoBuild { source }
                    })?;
                if let Err(source) = self.start_readiness_bridge_if_needed(true) {
                    return match packet_io.stop() {
                        Ok(()) => Err(ProcessNetworkPacketIoProviderBuildError::ReadinessBridge {
                            source,
                        }),
                        Err(_) => Err(ProcessNetworkPacketIoProviderBuildError::CleanupUncertain),
                    };
                }
                if let Err(source) = packet_io.enable_packet_available_callback(packet_callback) {
                    return match packet_io.stop() {
                        Ok(()) => {
                            Err(ProcessNetworkPacketIoProviderBuildError::PacketEvents { source })
                        }
                        Err(_) => Err(ProcessNetworkPacketIoProviderBuildError::CleanupUncertain),
                    };
                }
                (
                    ProcessNetworkPacketIo::Vmnet(Box::new(packet_io)),
                    NetworkDeviceProfile::new(Some(realized_mac), config.mtu())
                        .with_packet_envelope(packet_envelope),
                    Some(parameters),
                    !explicit_mac_pre_reserved,
                )
            }
        };
        self.next_generation = next_generation;
        Ok(PreparedProcessNetworkPacketIoEntry {
            entry: ProcessNetworkPacketIoEntry {
                owner: self.owner,
                generation,
                iface_id: iface_id.to_string(),
                packet_io,
                device_profile,
                backend_parameters,
            },
            reserve_realized_mac,
        })
    }

    fn publish_prepared(
        &mut self,
        prepared: PreparedProcessNetworkPacketIoEntry<B>,
    ) -> PublishedProcessNetworkPacketIoEntry {
        assert_eq!(
            prepared.entry.owner, self.owner,
            "prepared network packet-I/O owner must match its registry"
        );
        assert!(
            !self
                .entries
                .iter()
                .any(|entry| entry.iface_id == prepared.entry.iface_id),
            "prepared network packet-I/O publication must remain unique"
        );
        assert!(
            self.entries.len() < bangbang_runtime::network::MAX_NETWORK_INTERFACE_COUNT
                && self.entries.len() < self.entries.capacity(),
            "prepared network packet-I/O publication must retain reserved capacity"
        );
        if prepared.reserve_realized_mac
            && let Some(mac) = prepared.entry.device_profile.guest_mac()
        {
            assert!(
                !self.reserved_macs.contains(&mac),
                "prepared network MAC publication must remain unique"
            );
            assert!(
                self.reserved_macs.len() < bangbang_runtime::network::MAX_NETWORK_INTERFACE_COUNT
                    && self.reserved_macs.len() < self.reserved_macs.capacity(),
                "prepared network MAC publication must retain reserved capacity"
            );
            self.reserved_macs.push(mac);
        }
        let published = PublishedProcessNetworkPacketIoEntry {
            owner: prepared.entry.owner,
            generation: prepared.entry.generation,
            iface_id: prepared.entry.iface_id.clone(),
        };
        self.entries.push(prepared.entry);
        published
    }

    fn take_interface(
        &mut self,
        iface_id: &str,
    ) -> Result<RemovedProcessNetworkPacketIoEntry<B>, ProcessNetworkPacketIoRegistryError> {
        let index = self
            .entries
            .iter()
            .position(|entry| entry.iface_id == iface_id)
            .ok_or(ProcessNetworkPacketIoRegistryError::UnknownInterface)?;
        let entry = self
            .entries
            .get(index)
            .ok_or(ProcessNetworkPacketIoRegistryError::UnknownInterface)?;
        if entry.owner != self.owner {
            return Err(ProcessNetworkPacketIoRegistryError::AuthorityMismatch);
        }
        self.release_reserved_mac_for_entry(index)?;
        Ok(RemovedProcessNetworkPacketIoEntry {
            index,
            entry: self.entries.remove(index),
        })
    }

    fn take_published(
        &mut self,
        published: &PublishedProcessNetworkPacketIoEntry,
    ) -> Result<RemovedProcessNetworkPacketIoEntry<B>, ProcessNetworkPacketIoRegistryError> {
        if published.owner != self.owner {
            return Err(ProcessNetworkPacketIoRegistryError::AuthorityMismatch);
        }
        let index = self
            .entries
            .iter()
            .position(|entry| {
                entry.generation == published.generation && entry.iface_id == published.iface_id
            })
            .ok_or(ProcessNetworkPacketIoRegistryError::UnknownInterface)?;
        let entry = self
            .entries
            .get(index)
            .ok_or(ProcessNetworkPacketIoRegistryError::UnknownInterface)?;
        if entry.owner != self.owner {
            return Err(ProcessNetworkPacketIoRegistryError::AuthorityMismatch);
        }
        self.release_reserved_mac_for_entry(index)?;
        Ok(RemovedProcessNetworkPacketIoEntry {
            index,
            entry: self.entries.remove(index),
        })
    }

    fn restore_removed(
        &mut self,
        removed: RemovedProcessNetworkPacketIoEntry<B>,
    ) -> Result<(), ProcessNetworkPacketIoRegistryError> {
        if removed.entry.owner != self.owner {
            return Err(ProcessNetworkPacketIoRegistryError::AuthorityMismatch);
        }
        if self
            .entries
            .iter()
            .any(|entry| entry.iface_id == removed.entry.iface_id)
        {
            return Err(ProcessNetworkPacketIoRegistryError::DuplicateInterface);
        }
        if self.entries.len() == bangbang_runtime::network::MAX_NETWORK_INTERFACE_COUNT
            || removed.index > self.entries.len()
        {
            return Err(ProcessNetworkPacketIoRegistryError::Capacity);
        }
        if let Some(mac) = removed.entry.device_profile.guest_mac() {
            if self.reserved_macs.contains(&mac) {
                return Err(ProcessNetworkPacketIoRegistryError::DuplicateRealizedMac);
            }
            if self.reserved_macs.len() == bangbang_runtime::network::MAX_NETWORK_INTERFACE_COUNT {
                return Err(ProcessNetworkPacketIoRegistryError::Capacity);
            }
            self.reserved_macs.push(mac);
        }
        self.entries.insert(removed.index, removed.entry);
        Ok(())
    }

    fn release_reserved_mac_for_entry(
        &mut self,
        entry_index: usize,
    ) -> Result<(), ProcessNetworkPacketIoRegistryError> {
        let Some(mac) = self
            .entries
            .get(entry_index)
            .and_then(|entry| entry.device_profile.guest_mac())
        else {
            return Ok(());
        };
        let reservation_index = self
            .reserved_macs
            .iter()
            .position(|reserved| *reserved == mac)
            .ok_or(ProcessNetworkPacketIoRegistryError::MissingRealizedMac)?;
        self.reserved_macs.remove(reservation_index);
        Ok(())
    }

    #[cfg(test)]
    fn quiesce_capture_publication(
        &self,
    ) -> Result<ProcessNetworkPacketIoPublicationQuiescenceGuard, ProcessCaptureReadyNetworkError>
    {
        self.quiesce_capture_publication_for_owner(ProcessVmnetAuthority::Direct)
    }

    fn quiesce_capture_publication_for_owner(
        &self,
        owner: ProcessVmnetAuthority,
    ) -> Result<ProcessNetworkPacketIoPublicationQuiescenceGuard, ProcessCaptureReadyNetworkError>
    {
        if owner != self.owner
            || self.entries.iter().any(|entry| entry.owner != self.owner)
            || self
                .readiness_bridge
                .as_ref()
                .is_some_and(|bridge| bridge.owner != self.owner)
        {
            return Err(ProcessCaptureReadyNetworkError::AuthorityMismatch);
        }
        let mut guards = Vec::new();
        guards
            .try_reserve_exact(self.vmnet_count())
            .map_err(|_| ProcessCaptureReadyNetworkError::Allocation)?;
        for entry in &self.entries {
            let Some(guard) = entry
                .packet_io
                .quiesce_readiness_publication()
                .map_err(|_| ProcessCaptureReadyNetworkError::PublicationQuiescence)?
            else {
                continue;
            };
            if guard.generation() != entry.generation {
                return Err(ProcessCaptureReadyNetworkError::GenerationMismatch);
            }
            guards.push(guard);
        }
        Ok(ProcessNetworkPacketIoPublicationQuiescenceGuard { _guards: guards })
    }

    #[cfg(test)]
    fn prepare_capture(
        &self,
        configs: &[NetworkInterfaceConfig],
        mmds_config: Option<&MmdsConfig>,
        mmds_state: &MmdsStateHandle,
        mmds_metrics: Option<&SharedMmdsMetrics>,
        now: Instant,
    ) -> Result<PreparedProcessNetworkCapture, ProcessCaptureReadyNetworkError> {
        self.prepare_capture_for_owner(
            ProcessVmnetAuthority::Direct,
            configs,
            mmds_config,
            mmds_state,
            mmds_metrics,
            now,
        )
    }

    fn prepare_capture_for_owner(
        &self,
        owner: ProcessVmnetAuthority,
        configs: &[NetworkInterfaceConfig],
        mmds_config: Option<&MmdsConfig>,
        mmds_state: &MmdsStateHandle,
        mmds_metrics: Option<&SharedMmdsMetrics>,
        now: Instant,
    ) -> Result<PreparedProcessNetworkCapture, ProcessCaptureReadyNetworkError> {
        self.validate_capture_authority(configs, owner)?;
        if self.entries.len() != configs.len() {
            return Err(ProcessCaptureReadyNetworkError::InventoryMismatch);
        }
        let live_mmds_config = mmds_state
            .config()
            .map_err(|source| ProcessCaptureReadyNetworkError::MmdsState { source })?;
        let mmds = match (mmds_config, self.mmds_detour.as_ref(), mmds_metrics) {
            (None, None, None) if live_mmds_config.is_none() => None,
            (Some(config), Some(detour), Some(metrics)) => {
                if !detour.mmds_state.shares_state_with(mmds_state)
                    || !detour.metrics.shares_state_with(metrics)
                    || detour.mmds_ipv4_address != config.effective_ipv4_address()
                    || detour.network_interfaces != config.network_interfaces()
                    || live_mmds_config.as_ref() != Some(config)
                {
                    return Err(ProcessCaptureReadyNetworkError::MmdsMismatch);
                }
                Some(ProcessCaptureReadyMmdsState {
                    config: config.clone(),
                    metrics: metrics.snapshot(),
                })
            }
            _ => return Err(ProcessCaptureReadyNetworkError::MmdsMismatch),
        };
        if mmds_config.is_some_and(|mmds| {
            mmds.network_interfaces().iter().any(|selected| {
                configs
                    .iter()
                    .filter(|config| config.iface_id() == selected)
                    .count()
                    != 1
            })
        }) {
            return Err(ProcessCaptureReadyNetworkError::MmdsMismatch);
        }

        let mut entries = Vec::new();
        entries
            .try_reserve_exact(configs.len())
            .map_err(|_| ProcessCaptureReadyNetworkError::Allocation)?;
        let mut hvf_configs = Vec::new();
        hvf_configs
            .try_reserve_exact(configs.len())
            .map_err(|_| ProcessCaptureReadyNetworkError::Allocation)?;
        let mut generations = Vec::new();
        generations
            .try_reserve_exact(configs.len())
            .map_err(|_| ProcessCaptureReadyNetworkError::Allocation)?;
        let mut expected_macs = Vec::new();
        expected_macs
            .try_reserve_exact(configs.len())
            .map_err(|_| ProcessCaptureReadyNetworkError::Allocation)?;

        for config in configs {
            let mut matches = self
                .entries
                .iter()
                .filter(|entry| entry.iface_id == config.iface_id());
            let entry = matches
                .next()
                .ok_or(ProcessCaptureReadyNetworkError::InventoryMismatch)?;
            if matches.next().is_some() || entry.generation >= self.next_generation {
                return Err(ProcessCaptureReadyNetworkError::GenerationMismatch);
            }
            if generations.contains(&entry.generation) {
                return Err(ProcessCaptureReadyNetworkError::GenerationMismatch);
            }
            generations.push(entry.generation);
            if entry.packet_io.capture_tx_transaction_active() {
                return Err(ProcessCaptureReadyNetworkError::PacketTransactionInFlight);
            }

            if let Some(mac) = entry.device_profile.guest_mac() {
                if expected_macs.contains(&mac) {
                    return Err(ProcessCaptureReadyNetworkError::ReservedMacMismatch);
                }
                expected_macs.push(mac);
            }

            let backend = match (&entry.packet_io, entry.backend_parameters.as_ref()) {
                (ProcessNetworkPacketIo::MmdsOnly(_), None)
                    if entry.device_profile == NetworkDeviceProfile::from_config(config) =>
                {
                    ProcessCaptureReadyNetworkBackend::MmdsOnly
                }
                (ProcessNetworkPacketIo::Vmnet(_), Some(parameters)) => {
                    let expected_envelope = if parameters.direct_virtio_header_enabled() {
                        VirtioNetworkPacketEnvelope::DirectVirtioHeader
                    } else {
                        VirtioNetworkPacketEnvelope::RawEthernet
                    };
                    if entry.device_profile.guest_mac() != Some(parameters.realized_mac())
                        || entry.device_profile.mtu() != config.mtu()
                        || entry.device_profile.packet_envelope() != expected_envelope
                        || entry.device_profile.feature_capabilities()
                            != bangbang_runtime::network::VirtioNetworkFeatureCapabilities::complete_software()
                        || config
                            .guest_mac()
                            .is_some_and(|mac| mac != parameters.realized_mac())
                        || config
                            .mtu()
                            .is_some_and(|mtu| mtu != parameters.effective_mtu())
                        || parameters.maximum_packet_size() == 0
                        || parameters.packet_buffer_size().is_none()
                        || (parameters.direct_virtio_header_enabled()
                            && !parameters.direct_virtio_header_available())
                    {
                        return Err(ProcessCaptureReadyNetworkError::BackendMismatch);
                    }
                    ProcessCaptureReadyNetworkBackend::Vmnet(parameters.clone())
                }
                _ => return Err(ProcessCaptureReadyNetworkError::BackendMismatch),
            };

            let selected_for_mmds = mmds_config.is_some_and(|mmds| {
                mmds.network_interfaces()
                    .iter()
                    .any(|iface_id| iface_id == config.iface_id())
            });
            let stack = entry.packet_io.capture_mmds_stack();
            if stack.is_some() != selected_for_mmds
                || matches!(backend, ProcessCaptureReadyNetworkBackend::MmdsOnly)
                    && !selected_for_mmds
            {
                return Err(ProcessCaptureReadyNetworkError::MmdsMismatch);
            }
            let mmds_stack = match (stack, mmds_metrics) {
                (Some(stack), Some(metrics)) => Some(
                    stack
                        .capture_descriptor(mmds_state, metrics)
                        .map_err(|source| ProcessCaptureReadyNetworkError::MmdsStack { source })?,
                ),
                (None, _) => None,
                (Some(_), None) => return Err(ProcessCaptureReadyNetworkError::MmdsMismatch),
            };
            let provider_cached_rx_len = entry.packet_io.capture_cached_rx_len();
            let provider_retry_after = entry.packet_io.packet_retry_after_at(now);
            let provider_mmds_ready = entry.packet_io.capture_mmds_ready_at(now);
            hvf_configs.push(HvfArm64BootNetworkCaptureConfig::new(
                config.clone(),
                entry.device_profile,
                provider_cached_rx_len,
                provider_retry_after,
                provider_mmds_ready,
            ));
            entries.push(ProcessNetworkPacketIoCaptureEntry {
                generation: entry.generation,
                backend,
                mmds_stack,
            });
        }

        if expected_macs.len() != self.reserved_macs.len()
            || expected_macs
                .iter()
                .any(|mac| !self.reserved_macs.contains(mac))
        {
            return Err(ProcessCaptureReadyNetworkError::ReservedMacMismatch);
        }

        Ok(PreparedProcessNetworkCapture {
            entries,
            hvf_configs,
            provider_next_generation: self.next_generation,
            mmds,
        })
    }

    fn validate_capture_authority(
        &self,
        configs: &[NetworkInterfaceConfig],
        owner: ProcessVmnetAuthority,
    ) -> Result<(), ProcessCaptureReadyNetworkError> {
        if owner != self.owner || self.entries.iter().any(|entry| entry.owner != self.owner) {
            return Err(ProcessCaptureReadyNetworkError::AuthorityMismatch);
        }
        let Some(authority) = owner.contained_authority() else {
            return Ok(());
        };
        let vmnet_count = self.vmnet_count();
        if vmnet_count == 0 {
            return Ok(());
        }
        if vmnet_count
            > usize::from(
                authority
                    .max_interfaces()
                    .ok_or(ProcessCaptureReadyNetworkError::AuthorityMismatch)?,
            )
        {
            return Err(ProcessCaptureReadyNetworkError::AuthorityMismatch);
        }
        for config in configs {
            let mut matches = self
                .entries
                .iter()
                .filter(|entry| entry.iface_id == config.iface_id());
            let entry = matches
                .next()
                .ok_or(ProcessCaptureReadyNetworkError::InventoryMismatch)?;
            if matches.next().is_some() {
                return Err(ProcessCaptureReadyNetworkError::InventoryMismatch);
            }
            if !entry.packet_io.is_vmnet() {
                continue;
            }
            let vmnet = VmnetInterfaceConfig::from_host_dev_name(config.host_dev_name())
                .map_err(|_| ProcessCaptureReadyNetworkError::AuthorityMismatch)?;
            if !vmnet_authority_allows(authority, &vmnet) {
                return Err(ProcessCaptureReadyNetworkError::AuthorityMismatch);
            }
        }
        Ok(())
    }

    fn device_profiles(&self) -> BTreeMap<String, NetworkDeviceProfile> {
        self.entries
            .iter()
            .map(|entry| (entry.iface_id.clone(), entry.device_profile))
            .collect()
    }

    fn cleanup_after_build_error(
        &mut self,
        source: ProcessNetworkPacketIoProviderBuildError,
    ) -> ProcessNetworkPacketIoProviderBuildError {
        if self.stop_all() {
            ProcessNetworkPacketIoProviderBuildError::CleanupUncertain
        } else {
            source
        }
    }

    fn stop_all(&mut self) -> bool {
        let mut uncertain = false;
        for entry in self.entries.iter_mut().rev() {
            if entry.packet_io.stop().is_err() {
                uncertain = true;
            }
        }
        uncertain
    }

    fn bind_readiness_wake(
        &mut self,
        wake: Arc<dyn Fn() + Send + Sync + 'static>,
    ) -> Result<(), BackendError> {
        if self.readiness_wake.is_some() {
            return Err(BackendError::InvalidState(
                "vmnet readiness wake target is already bound",
            ));
        }
        self.readiness_wake = Some(wake);
        self.start_readiness_bridge_if_needed(false)
    }

    fn start_readiness_bridge_if_needed(
        &mut self,
        preparing_vmnet: bool,
    ) -> Result<(), BackendError> {
        if self.readiness_bridge.is_some()
            || self.readiness_wake.is_none()
            || (!preparing_vmnet && self.vmnet_count() == 0)
        {
            return Ok(());
        }
        let receiver = self
            .readiness_receiver
            .take()
            .ok_or(BackendError::InvalidState(
                "vmnet readiness receiver is unavailable",
            ))?;
        let wake = self
            .readiness_wake
            .as_ref()
            .cloned()
            .ok_or(BackendError::InvalidState(
                "vmnet readiness wake target is unavailable",
            ))?;
        self.readiness_bridge = Some(ProcessNetworkPacketReadinessBridge::start(
            self.owner,
            receiver,
            self.readiness_signal.clone(),
            wake,
        )?);
        Ok(())
    }

    fn shutdown_packet_io(&mut self) -> Result<(), BackendError> {
        let packet_io_uncertain = self.stop_all();
        let bridge_result = match self.readiness_bridge.take() {
            Some(mut bridge) => bridge.stop(),
            None => Ok(()),
        };
        self.readiness_wake = None;
        if packet_io_uncertain {
            return Err(BackendError::InvalidState(
                "vmnet packet-I/O cleanup could not be confirmed",
            ));
        }
        bridge_result
    }

    fn vmnet_count(&self) -> usize {
        self.entries
            .iter()
            .filter(|entry| entry.packet_io.is_vmnet())
            .count()
    }
}

impl<B> Drop for ProcessNetworkPacketIoRegistry<B>
where
    B: ProcessVmnetBackend,
{
    fn drop(&mut self) {
        let _ = self.shutdown_packet_io();
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ProcessNetworkPacketIoEntryClass {
    MmdsOnly,
    Vmnet,
}

#[derive(Debug)]
pub(crate) enum ProcessNetworkPacketIoRegistryError {
    AuthorityMismatch,
    DuplicateInterface,
    DuplicateRealizedMac,
    MissingRealizedMac,
    UnknownInterface,
    Capacity,
}

impl fmt::Display for ProcessNetworkPacketIoRegistryError {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::AuthorityMismatch => {
                formatter.write_str("network packet-I/O lifecycle owner is inconsistent")
            }
            Self::DuplicateInterface => {
                formatter.write_str("network packet-I/O interface is already registered")
            }
            Self::DuplicateRealizedMac => {
                formatter.write_str("network packet-I/O guest identity is already reserved")
            }
            Self::MissingRealizedMac => {
                formatter.write_str("network packet-I/O guest identity reservation is missing")
            }
            Self::UnknownInterface => {
                formatter.write_str("network packet-I/O interface is not registered")
            }
            Self::Capacity => formatter.write_str("network packet-I/O registry is full"),
        }
    }
}

impl std::error::Error for ProcessNetworkPacketIoRegistryError {}

#[derive(Debug)]
pub(crate) enum ProcessNetworkPacketIoStopError {
    Vmnet {
        source: VmnetVirtioNetworkPacketIoStopError,
    },
}

impl fmt::Display for ProcessNetworkPacketIoStopError {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::Vmnet { source } => write!(formatter, "{source}"),
        }
    }
}

impl std::error::Error for ProcessNetworkPacketIoStopError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            Self::Vmnet { source } => Some(source),
        }
    }
}

pub(crate) trait ProcessRuntimeNetworkPacketIoProvider:
    Arm64BootNetworkPacketIoProvider
{
    type PreparedEntry;
    type PublishedEntry;
    type RemovedEntry;

    fn bind_readiness_wake(
        &mut self,
        _wake: Arc<dyn Fn() + Send + Sync + 'static>,
    ) -> Result<(), BackendError> {
        Ok(())
    }

    fn shutdown_packet_io(&mut self) -> Result<(), BackendError> {
        Ok(())
    }

    fn prepare_runtime_entry(
        &mut self,
        config: &NetworkInterfaceConfig,
        authority: ProcessVmnetAuthority,
    ) -> Result<(Self::PreparedEntry, NetworkDeviceProfile), NetworkRuntimeMutationError>;

    fn publish_prepared_entry(&mut self, prepared: Self::PreparedEntry) -> Self::PublishedEntry;

    fn take_published_entry(
        &mut self,
        published: &Self::PublishedEntry,
    ) -> Result<Self::RemovedEntry, ProcessNetworkPacketIoRegistryError>;

    fn take_interface_entry(
        &mut self,
        iface_id: &str,
    ) -> Result<Self::RemovedEntry, ProcessNetworkPacketIoRegistryError>;

    fn stop_removed_entry(
        removed: &mut Self::RemovedEntry,
    ) -> Result<(), ProcessNetworkPacketIoStopError>;

    fn restore_removed_entry(
        &mut self,
        removed: Self::RemovedEntry,
    ) -> Result<(), ProcessNetworkPacketIoRegistryError>;
}

impl ProcessRuntimeNetworkPacketIoProvider for ProcessNetworkPacketIoProvider {
    type PreparedEntry = PreparedProcessNetworkPacketIoEntry<SystemVmnetInterfaceBackend>;
    type PublishedEntry = PublishedProcessNetworkPacketIoEntry;
    type RemovedEntry = RemovedProcessNetworkPacketIoEntry<SystemVmnetInterfaceBackend>;

    fn bind_readiness_wake(
        &mut self,
        wake: Arc<dyn Fn() + Send + Sync + 'static>,
    ) -> Result<(), BackendError> {
        ProcessNetworkPacketIoRegistry::bind_readiness_wake(self, wake)
    }

    fn shutdown_packet_io(&mut self) -> Result<(), BackendError> {
        ProcessNetworkPacketIoRegistry::shutdown_packet_io(self)
    }

    fn prepare_runtime_entry(
        &mut self,
        config: &NetworkInterfaceConfig,
        authority: ProcessVmnetAuthority,
    ) -> Result<(Self::PreparedEntry, NetworkDeviceProfile), NetworkRuntimeMutationError> {
        let prepared =
            ProcessNetworkPacketIoRegistry::prepare_runtime_entry(self, config, authority)?;
        let profile = prepared.device_profile();
        Ok((prepared, profile))
    }

    fn publish_prepared_entry(&mut self, prepared: Self::PreparedEntry) -> Self::PublishedEntry {
        self.publish_prepared(prepared)
    }

    fn take_published_entry(
        &mut self,
        published: &Self::PublishedEntry,
    ) -> Result<Self::RemovedEntry, ProcessNetworkPacketIoRegistryError> {
        self.take_published(published)
    }

    fn take_interface_entry(
        &mut self,
        iface_id: &str,
    ) -> Result<Self::RemovedEntry, ProcessNetworkPacketIoRegistryError> {
        self.take_interface(iface_id)
    }

    fn stop_removed_entry(
        removed: &mut Self::RemovedEntry,
    ) -> Result<(), ProcessNetworkPacketIoStopError> {
        removed.stop()
    }

    fn restore_removed_entry(
        &mut self,
        removed: Self::RemovedEntry,
    ) -> Result<(), ProcessNetworkPacketIoRegistryError> {
        self.restore_removed(removed)
    }
}

#[derive(Debug, Clone)]
struct ProcessMmdsPacketDetourConfig {
    mmds_state: MmdsStateHandle,
    mmds_ipv4_address: Ipv4Addr,
    network_interfaces: Vec<String>,
    metrics: SharedMmdsMetrics,
}

impl ProcessMmdsPacketDetourConfig {
    fn from_mmds_config(
        mmds_state: MmdsStateHandle,
        config: &MmdsConfig,
        metrics: SharedMmdsMetrics,
    ) -> Self {
        Self {
            mmds_state,
            mmds_ipv4_address: config.effective_ipv4_address(),
            network_interfaces: config.network_interfaces().to_vec(),
            metrics,
        }
    }

    fn detour_for_interface(
        &self,
        iface_id: &str,
    ) -> Result<Option<MmdsPacketDetour>, MmdsNetworkStackBuildError> {
        if !self
            .network_interfaces
            .iter()
            .any(|configured_iface_id| configured_iface_id == iface_id)
        {
            return Ok(None);
        }

        MmdsPacketDetour::try_new(
            self.mmds_state.clone(),
            self.mmds_ipv4_address,
            self.metrics.clone(),
        )
        .map(Some)
    }

    fn covers_all_interfaces(&self, configs: &[NetworkInterfaceConfig]) -> bool {
        configs
            .iter()
            .all(|config| self.interface_is_configured(config.iface_id()))
    }

    fn interface_is_configured(&self, iface_id: &str) -> bool {
        self.network_interfaces
            .iter()
            .any(|configured_iface_id| configured_iface_id == iface_id)
    }
}

impl<B> Arm64BootNetworkPacketIoProvider for ProcessNetworkPacketIoRegistry<B>
where
    B: ProcessVmnetBackend,
{
    fn take_scheduled_packet_readiness(&mut self) -> bool {
        let mut scheduled = false;
        for entry in &self.entries {
            scheduled |= entry.packet_io.take_scheduled_readiness();
        }
        scheduled
    }

    fn has_packet_readiness(&self, interface: Arm64BootNetworkInterface<'_>) -> bool {
        self.entries
            .iter()
            .find(|entry| entry.iface_id == interface.iface_id())
            .is_some_and(|entry| entry.packet_io.has_persistent_readiness())
    }

    fn packet_retry_after(&self, interface: Arm64BootNetworkInterface<'_>) -> Option<Duration> {
        self.entries
            .iter()
            .find(|entry| entry.iface_id == interface.iface_id())
            .and_then(|entry| entry.packet_io.packet_retry_after())
    }

    fn packet_io(
        &mut self,
        interface: Arm64BootNetworkInterface<'_>,
    ) -> Result<Arm64BootNetworkPacketIo<'_>, Arm64BootNetworkPacketIoError> {
        let iface_id = interface.iface_id();
        self.entries
            .iter_mut()
            .find(|entry| entry.iface_id == iface_id)
            .map(|entry| entry.packet_io.as_packet_io())
            .ok_or_else(|| {
                Arm64BootNetworkPacketIoError::new(format!(
                    "missing process packet I/O for interface {iface_id}"
                ))
            })
    }
}

enum ProcessNetworkPacketIoProviderBuildError {
    AuthorityMismatch,
    NetworkInterfaceCount {
        source: NetworkInterfaceConfigError,
    },
    DuplicateInterface,
    DuplicateRealizedMac,
    ProviderCapacity {
        source: TryReserveError,
    },
    RegistryCapacity,
    GenerationExhausted,
    MmdsState {
        source: MmdsStateLockError,
    },
    MmdsNetworkStack {
        source: MmdsNetworkStackBuildError,
    },
    HostDeviceName {
        source: VmnetHostDeviceNameConfigError,
    },
    Start {
        source: VmnetInterfaceStartError,
    },
    PacketIoBuild {
        source: VmnetVirtioNetworkPacketIoBuildError,
    },
    ReadinessBridge {
        source: BackendError,
    },
    PacketEvents {
        source: VmnetVirtioNetworkPacketIoStopError,
    },
    CleanupUncertain,
    MmdsOnlyPacketIoBuild {
        source: MmdsOnlyVirtioNetworkPacketIoBuildError,
    },
    MissingMmdsDetour,
}

impl fmt::Debug for ProcessNetworkPacketIoProviderBuildError {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(match self {
            Self::AuthorityMismatch => {
                "ProcessNetworkPacketIoProviderBuildError::AuthorityMismatch"
            }
            Self::NetworkInterfaceCount { .. } => {
                "ProcessNetworkPacketIoProviderBuildError::NetworkInterfaceCount"
            }
            Self::DuplicateInterface => {
                "ProcessNetworkPacketIoProviderBuildError::DuplicateInterface"
            }
            Self::DuplicateRealizedMac => {
                "ProcessNetworkPacketIoProviderBuildError::DuplicateRealizedMac"
            }
            Self::ProviderCapacity { .. } => {
                "ProcessNetworkPacketIoProviderBuildError::ProviderCapacity"
            }
            Self::RegistryCapacity => "ProcessNetworkPacketIoProviderBuildError::RegistryCapacity",
            Self::GenerationExhausted => {
                "ProcessNetworkPacketIoProviderBuildError::GenerationExhausted"
            }
            Self::MmdsState { .. } => "ProcessNetworkPacketIoProviderBuildError::MmdsState",
            Self::MmdsNetworkStack { .. } => {
                "ProcessNetworkPacketIoProviderBuildError::MmdsNetworkStack"
            }
            Self::HostDeviceName { .. } => {
                "ProcessNetworkPacketIoProviderBuildError::HostDeviceName"
            }
            Self::Start { .. } => "ProcessNetworkPacketIoProviderBuildError::Start",
            Self::PacketIoBuild { .. } => "ProcessNetworkPacketIoProviderBuildError::PacketIoBuild",
            Self::ReadinessBridge { .. } => {
                "ProcessNetworkPacketIoProviderBuildError::ReadinessBridge"
            }
            Self::PacketEvents { .. } => "ProcessNetworkPacketIoProviderBuildError::PacketEvents",
            Self::CleanupUncertain => "ProcessNetworkPacketIoProviderBuildError::CleanupUncertain",
            Self::MmdsOnlyPacketIoBuild { .. } => {
                "ProcessNetworkPacketIoProviderBuildError::MmdsOnlyPacketIoBuild"
            }
            Self::MissingMmdsDetour => {
                "ProcessNetworkPacketIoProviderBuildError::MissingMmdsDetour"
            }
        })
    }
}

impl ProcessNetworkPacketIoProviderBuildError {
    fn is_terminal(&self) -> bool {
        match self {
            Self::Start { source, .. } => {
                source.disposition() == VmnetInterfaceStartDisposition::Terminal
            }
            Self::AuthorityMismatch | Self::CleanupUncertain | Self::ReadinessBridge { .. } => true,
            Self::NetworkInterfaceCount { .. }
            | Self::DuplicateInterface
            | Self::DuplicateRealizedMac
            | Self::ProviderCapacity { .. }
            | Self::RegistryCapacity
            | Self::GenerationExhausted
            | Self::MmdsState { .. }
            | Self::MmdsNetworkStack { .. }
            | Self::HostDeviceName { .. }
            | Self::PacketIoBuild { .. }
            | Self::PacketEvents { .. }
            | Self::MmdsOnlyPacketIoBuild { .. }
            | Self::MissingMmdsDetour => false,
        }
    }
}

impl fmt::Display for ProcessNetworkPacketIoProviderBuildError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::AuthorityMismatch => {
                f.write_str("network packet-I/O lifecycle owner is inconsistent")
            }
            Self::NetworkInterfaceCount { source } => {
                write!(f, "unsupported network interface count: {source}")
            }
            Self::DuplicateInterface => {
                f.write_str("network packet I/O interface is already configured")
            }
            Self::DuplicateRealizedMac => {
                f.write_str("network packet I/O guest identity is already reserved")
            }
            Self::ProviderCapacity { source } => {
                write!(f, "failed to reserve network packet I/O registry: {source}")
            }
            Self::RegistryCapacity => f.write_str("network packet I/O registry is full"),
            Self::GenerationExhausted => {
                f.write_str("network packet I/O ownership generation is exhausted")
            }
            Self::MmdsState { source } => {
                write!(f, "failed to access MMDS state: {source}")
            }
            Self::MmdsNetworkStack { source } => {
                write!(f, "failed to build MMDS network stack: {source}")
            }
            Self::HostDeviceName { source } => {
                write!(
                    f,
                    "network interface has unsupported vmnet host device config: {source}"
                )
            }
            Self::Start { source } => {
                write!(f, "failed to start vmnet packet I/O: {source}")
            }
            Self::PacketIoBuild { source } => {
                write!(f, "failed to build vmnet packet I/O: {source}")
            }
            Self::ReadinessBridge { source } => {
                write!(f, "failed to bind vmnet packet readiness: {source}")
            }
            Self::PacketEvents { source } => {
                write!(f, "failed to enable vmnet packet events: {source}")
            }
            Self::CleanupUncertain => {
                f.write_str("vmnet packet I/O cleanup could not be confirmed")
            }
            Self::MmdsOnlyPacketIoBuild { source } => {
                write!(f, "failed to build MMDS-only packet I/O: {source}")
            }
            Self::MissingMmdsDetour => {
                f.write_str("missing MMDS packet detour for network interface")
            }
        }
    }
}

impl std::error::Error for ProcessNetworkPacketIoProviderBuildError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            Self::NetworkInterfaceCount { source } => Some(source),
            Self::ProviderCapacity { source } => Some(source),
            Self::MmdsState { source } => Some(source),
            Self::MmdsNetworkStack { source } => Some(source),
            Self::HostDeviceName { source, .. } => Some(source),
            Self::Start { source, .. } => Some(source),
            Self::PacketIoBuild { source, .. } => Some(source),
            Self::ReadinessBridge { source, .. } => Some(source),
            Self::PacketEvents { source, .. } => Some(source),
            Self::MmdsOnlyPacketIoBuild { source, .. } => Some(source),
            Self::AuthorityMismatch
            | Self::DuplicateInterface
            | Self::DuplicateRealizedMac
            | Self::RegistryCapacity
            | Self::GenerationExhausted
            | Self::CleanupUncertain
            | Self::MissingMmdsDetour => None,
        }
    }
}

#[derive(Debug)]
enum ProcessVmnetAuthorityValidationError {
    Provider(ProcessNetworkPacketIoProviderBuildError),
    HostNetworkNotAuthorized,
}

fn process_vmnet_authority_action_error(
    error: ProcessVmnetAuthorityValidationError,
) -> VmmActionError {
    match error {
        ProcessVmnetAuthorityValidationError::HostNetworkNotAuthorized => {
            VmmActionError::NetworkInterfaceConfig(
                NetworkInterfaceConfigError::HostNetworkNotAuthorized,
            )
        }
        ProcessVmnetAuthorityValidationError::Provider(error) => {
            VmmActionError::InstanceStart(BackendError::Hypervisor(format!(
                "failed to build network packet I/O provider: {error}"
            )))
        }
    }
}

fn validate_process_vmnet_authority(
    controller: &VmmController,
    authority: ProcessVmnetAuthority,
) -> Result<(), ProcessVmnetAuthorityValidationError> {
    if matches!(authority, ProcessVmnetAuthority::Direct) {
        return Ok(());
    }
    let configs = controller.network_interface_configs();
    let mmds_config = controller.mmds_config().map_err(|source| {
        ProcessVmnetAuthorityValidationError::Provider(
            ProcessNetworkPacketIoProviderBuildError::MmdsState { source },
        )
    })?;
    let all_mmds = !configs.is_empty()
        && mmds_config.as_ref().is_some_and(|mmds| {
            configs.iter().all(|config| {
                mmds.network_interfaces()
                    .iter()
                    .any(|iface_id| iface_id == config.iface_id())
            })
        });

    validate_process_vmnet_authority_for_configs(configs, all_mmds, authority)
}

fn validate_process_vmnet_authority_for_configs(
    configs: &[NetworkInterfaceConfig],
    all_mmds: bool,
    authority: ProcessVmnetAuthority,
) -> Result<(), ProcessVmnetAuthorityValidationError> {
    validate_network_interface_count(configs.len()).map_err(|source| {
        ProcessVmnetAuthorityValidationError::Provider(
            ProcessNetworkPacketIoProviderBuildError::NetworkInterfaceCount { source },
        )
    })?;
    let contained_authority = authority.contained_authority();

    let required_authority = match (all_mmds, configs.is_empty()) {
        (true, _) | (_, true) => None,
        (false, false) => contained_authority,
    };
    if let Some(authority) = required_authority
        && configs.len()
            > usize::from(
                authority
                    .max_interfaces()
                    .ok_or(ProcessVmnetAuthorityValidationError::HostNetworkNotAuthorized)?,
            )
    {
        return Err(ProcessVmnetAuthorityValidationError::HostNetworkNotAuthorized);
    }

    for config in configs {
        let vmnet =
            VmnetInterfaceConfig::from_host_dev_name(config.host_dev_name()).map_err(|source| {
                ProcessVmnetAuthorityValidationError::Provider(
                    ProcessNetworkPacketIoProviderBuildError::HostDeviceName { source },
                )
            })?;
        let Some(authority) = required_authority else {
            continue;
        };
        if !vmnet_authority_allows(authority, &vmnet) {
            return Err(ProcessVmnetAuthorityValidationError::HostNetworkNotAuthorized);
        }
    }
    Ok(())
}

fn vmnet_authority_allows(authority: VmnetAuthority, vmnet: &VmnetInterfaceConfig) -> bool {
    match vmnet.mode() {
        VmnetMode::Host => authority.allows_host(),
        VmnetMode::Shared => authority.allows_shared(),
        VmnetMode::Bridged => vmnet
            .bridged_interface_name()
            .is_some_and(|bridge| authority.allows_bridge(bridge)),
    }
}

