impl<S> BootRunLoopSupervisor<S>
where
    S: BootRunLoopSession,
{
    #[cfg(test)]
    fn start(session: S, max_steps: NonZeroUsize) -> Result<Self, BackendError> {
        Self::start_recoverable(session, max_steps).map_err(BootRunLoopStartError::into_source)
    }

    fn start_recoverable(
        session: S,
        max_steps: NonZeroUsize,
    ) -> Result<Self, BootRunLoopStartError<S>> {
        Self::start_with_initial_state(
            session,
            max_steps,
            BOOT_RUN_LOOP_COMMAND_QUEUE_CAPACITY,
            false,
        )
    }

    #[cfg(test)]
    fn start_with_command_queue_capacity(
        session: S,
        max_steps: NonZeroUsize,
        command_queue_capacity: usize,
    ) -> Result<Self, BackendError> {
        Self::start_with_initial_state(session, max_steps, command_queue_capacity, false)
            .map_err(BootRunLoopStartError::into_source)
    }

    #[allow(
        dead_code,
        reason = "paused startup is reserved for internal native-v1 load"
    )]
    fn start_paused(session: S, max_steps: NonZeroUsize) -> Result<Self, BootRunLoopStartError<S>> {
        Self::start_with_initial_state(
            session,
            max_steps,
            BOOT_RUN_LOOP_COMMAND_QUEUE_CAPACITY,
            true,
        )
    }

    fn start_with_initial_state(
        mut session: S,
        max_steps: NonZeroUsize,
        command_queue_capacity: usize,
        initially_paused: bool,
    ) -> Result<Self, BootRunLoopStartError<S>> {
        let control = session.run_loop_control();
        let network_interface_updater = session.network_interface_updater();
        let balloon_device_updater = session.balloon_device_updater();
        let block_device_metrics = session.shared_block_device_metrics();
        let pmem_device_metrics = session.shared_pmem_device_metrics();
        let balloon_device_metrics = session.shared_balloon_device_metrics();
        let memory_hotplug_device_metrics = session.shared_memory_hotplug_device_metrics();
        let network_interface_metrics = session.shared_network_interface_metrics();
        let mmds_metrics = session.shared_mmds_metrics();
        let vsock_device_metrics = session.shared_vsock_device_metrics();
        let entropy_device_metrics = session.shared_entropy_device_metrics();
        let rtc_device_metrics = session.shared_rtc_device_metrics();
        let stop_token = control.stop_token();
        let status = Arc::new(BootRunLoopWorkerStatusCell::new());
        if initially_paused {
            status.record(BootRunLoopWorkerStatus::Paused);
        }
        let worker_status = Arc::clone(&status);
        let pause_gate = Arc::new(BootRunLoopPauseGate::default());
        if initially_paused {
            pause_gate.pause();
        }
        let worker_pause_gate = Arc::clone(&pause_gate);
        let admission = Arc::new(BootRunLoopCommandAdmission::default());
        let active_snapshot_cancellation = Arc::new(Mutex::new(None));
        let (command_sender, command_receiver) = mpsc::sync_channel(command_queue_capacity);
        let command_handle: BootRunLoopCommandHandle<S> = BootRunLoopCommandHandle::new(
            command_sender,
            control.clone(),
            Arc::clone(&status),
            Arc::clone(&pause_gate),
            Arc::clone(&admission),
        );
        let (terminal_wakeup_reader, mut terminal_wakeup_writer) = match UnixStream::pair() {
            Ok(pair) => pair,
            Err(err) => {
                return Err(BootRunLoopStartError::new(
                    BackendError::Hypervisor(format!(
                        "failed to create HVF boot run loop wakeup stream: {err}"
                    )),
                    session,
                ));
            }
        };
        if let Err(err) = terminal_wakeup_reader.set_nonblocking(true) {
            return Err(BootRunLoopStartError::new(
                BackendError::Hypervisor(format!(
                    "failed to configure HVF boot run loop wakeup stream: {err}"
                )),
                session,
            ));
        }
        let (session_release_sender, session_release_receiver) = mpsc::channel();
        let (session_sender, session_receiver) = mpsc::sync_channel::<S>(1);
        let worker = match thread::Builder::new()
            .name(HVF_BOOT_RUN_LOOP_THREAD_NAME.to_owned())
            .spawn(move || {
                let Ok(mut session) = session_receiver.recv() else {
                    return;
                };
                let worker_result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                    let mut observed_command_generation = worker_pause_gate.command_generation();
                    'worker: loop {
                        drain_boot_run_loop_commands(
                            &mut session,
                            &command_receiver,
                            command_queue_capacity,
                        );
                        loop {
                            match worker_pause_gate
                                .wait_once_if_paused(&mut observed_command_generation)
                            {
                                BootRunLoopPauseWait::Running => break,
                                BootRunLoopPauseWait::Paused => {
                                    drain_boot_run_loop_commands(
                                        &mut session,
                                        &command_receiver,
                                        command_queue_capacity,
                                    );
                                }
                                BootRunLoopPauseWait::Shutdown => {
                                    break 'worker None;
                                }
                            }
                        }
                        match session.run_loop(&stop_token, max_steps) {
                            Ok(outcome) if S::should_continue_after_outcome(&outcome) => continue,
                            Ok(outcome) => {
                                break 'worker Some(BootRunLoopWorkerStatus::Exited(
                                    outcome.clone(),
                                ));
                            }
                            Err(err) => {
                                break 'worker Some(BootRunLoopWorkerStatus::Failed(
                                    err.to_string(),
                                ));
                            }
                        }
                    }
                }));
                let intended_status = match worker_result {
                    Ok(status) => status,
                    Err(_) => Some(BootRunLoopWorkerStatus::Failed(
                        "boot run loop worker panicked".to_owned(),
                    )),
                };
                let cleanup_error = session.shutdown_run_loop_auxiliary_work().err();
                let final_status = match cleanup_error {
                    Some(source) => {
                        let prior = match intended_status.as_ref() {
                            Some(BootRunLoopWorkerStatus::Failed(message)) => {
                                format!("{message}; ")
                            }
                            Some(BootRunLoopWorkerStatus::Exited(_)) => {
                                "boot run loop exited; ".to_string()
                            }
                            Some(BootRunLoopWorkerStatus::Running)
                            | Some(BootRunLoopWorkerStatus::Paused)
                            | None => match worker_status.snapshot() {
                                BootRunLoopWorkerStatus::Failed(message) => {
                                    format!("{message}; ")
                                }
                                _ => String::new(),
                            },
                        };
                        Some(BootRunLoopWorkerStatus::Failed(format!(
                            "{prior}terminal network cleanup failed: {source}"
                        )))
                    }
                    None => intended_status,
                };
                if let Some(final_status) = final_status {
                    worker_status.record(final_status);
                    let _ = terminal_wakeup_writer.write_all(&[1]);
                } else if matches!(worker_status.snapshot(), BootRunLoopWorkerStatus::Failed(_)) {
                    let _ = terminal_wakeup_writer.write_all(&[1]);
                }
                drop(command_receiver);
                let _ = session_release_receiver.recv();
            }) {
            Ok(worker) => worker,
            Err(err) => {
                return Err(BootRunLoopStartError::new(
                    BackendError::Hypervisor(format!("failed to spawn HVF boot run loop: {err}")),
                    session,
                ));
            }
        };
        if let Err(source) = session.bind_run_loop_auxiliary_wakeup(control.clone()) {
            drop(session_sender);
            let _ = worker.join();
            return Err(BootRunLoopStartError::new(source, session));
        }
        if let Err(err) = session_sender.send(session) {
            let _ = worker.join();
            return Err(BootRunLoopStartError::new(
                BackendError::InvalidState("failed to hand off HVF boot run loop session"),
                err.0,
            ));
        }

        Ok(Self {
            control,
            network_interface_updater,
            balloon_device_updater,
            block_device_metrics,
            pmem_device_metrics,
            balloon_device_metrics,
            memory_hotplug_device_metrics,
            network_interface_metrics,
            mmds_metrics,
            vsock_device_metrics,
            entropy_device_metrics,
            rtc_device_metrics,
            command_handle,
            status,
            pause_gate,
            admission,
            active_snapshot_cancellation,
            terminal_wakeup_reader,
            session_release_sender: Some(session_release_sender),
            worker: Some(worker),
        })
    }

    #[cfg(test)]
    fn command_handle(&self) -> BootRunLoopCommandHandle<S> {
        self.command_handle.clone()
    }

    pub(crate) fn run_command<R, E>(
        &self,
        command: impl FnOnce(&mut S) -> Result<R, E> + Send + 'static,
    ) -> Result<R, BootRunLoopCommandError<<S::Control as BootRunLoopControl>::Error, E>>
    where
        R: Send + 'static,
        E: Send + 'static,
    {
        self.command_handle.run(command)
    }

    fn run_snapshot_quiesced<R, E>(
        &self,
        command: impl FnOnce(&mut S) -> Result<R, E> + Send + 'static,
    ) -> Result<R, BootRunLoopCommandError<<S::Control as BootRunLoopControl>::Error, E>>
    where
        R: Send + 'static,
        E: Send + 'static,
    {
        self.command_handle.run_snapshot_quiesced(command)
    }

    fn run_snapshot_quiesced_preserving_result_if<R, E>(
        &self,
        command: impl FnOnce(&mut S) -> Result<R, E> + Send + 'static,
        preserve_result: impl FnOnce() -> bool + Send + 'static,
    ) -> Result<R, BootRunLoopCommandError<<S::Control as BootRunLoopControl>::Error, E>>
    where
        R: Send + 'static,
        E: Send + 'static,
    {
        self.command_handle
            .run_snapshot_quiesced_preserving_result_if(command, preserve_result)
    }

    fn register_snapshot_capture(
        &self,
        cancellation: NativeV1SnapshotCaptureCancellation,
    ) -> Result<ActiveNativeV1SnapshotCapture, NativeV1SnapshotCaptureError> {
        let mut active = self.active_snapshot_cancellation.lock().map_err(|_| {
            NativeV1SnapshotCaptureError::Supervisor {
                source: BackendError::InvalidState(
                    "native-v1 snapshot cancellation registry is poisoned",
                ),
            }
        })?;
        if active.is_some() {
            return Err(NativeV1SnapshotCaptureError::Supervisor {
                source: BackendError::InvalidState(
                    "native-v1 snapshot capture is already registered",
                ),
            });
        }
        *active = Some(cancellation.clone());
        drop(active);
        Ok(ActiveNativeV1SnapshotCapture {
            registry: Arc::clone(&self.active_snapshot_cancellation),
            cancellation,
        })
    }

    fn cancel_active_snapshot_capture(&self) {
        if let Ok(active) = self.active_snapshot_cancellation.lock()
            && let Some(cancellation) = active.as_ref()
        {
            cancellation.cancel();
        }
    }

    #[cfg(test)]
    fn admission_state(&self) -> BootRunLoopCommandAdmissionState {
        self.admission.snapshot()
    }

    #[cfg(test)]
    fn wait_for_admission_state(&self, expected: BootRunLoopCommandAdmissionState) {
        self.admission.wait_for_state(expected);
    }

    fn status(&self) -> BootRunLoopWorkerStatus<S::Outcome> {
        self.status.snapshot()
    }

    #[cfg(test)]
    fn wait_for_terminal_status(&self) -> BootRunLoopWorkerStatus<S::Outcome> {
        self.status.wait_for_terminal_status()
    }

    fn metric_status(&self) -> BootRunLoopMetricStatus {
        let current = self.status.lock_status();
        match &*current {
            BootRunLoopWorkerStatus::Running => BootRunLoopMetricStatus::Running,
            BootRunLoopWorkerStatus::Paused => BootRunLoopMetricStatus::Paused,
            BootRunLoopWorkerStatus::Exited(_) => BootRunLoopMetricStatus::Exited,
            BootRunLoopWorkerStatus::Failed(_) => BootRunLoopMetricStatus::Failed,
        }
    }

    fn pause(&self) -> Result<(), BackendError> {
        if !matches!(self.status(), BootRunLoopWorkerStatus::Running) {
            return Err(BackendError::InvalidState(
                "boot run loop worker is not running",
            ));
        }

        let status = Arc::clone(&self.status);
        let pause_gate = Arc::clone(&self.pause_gate);
        self.run_command(move |_| {
            status.record(BootRunLoopWorkerStatus::Paused);
            pause_gate.pause();
            Ok(())
        })
        .map_err(lifecycle_error_from_boot_run_loop_command)
    }

    fn resume(&self) -> Result<(), BackendError> {
        if !matches!(self.status(), BootRunLoopWorkerStatus::Paused) {
            return Err(BackendError::InvalidState(
                "boot run loop worker is not paused",
            ));
        }

        let status = Arc::clone(&self.status);
        let pause_gate = Arc::clone(&self.pause_gate);
        self.run_command(move |_| {
            status.record(BootRunLoopWorkerStatus::Running);
            pause_gate.resume();
            Ok(())
        })
        .map_err(lifecycle_error_from_boot_run_loop_command)
    }

    fn record_block_device_update(&self, drive_id: &str) {
        if let Some(metrics) = &self.block_device_metrics {
            metrics.record_update_for_drive(drive_id);
        }
    }

    fn record_block_device_update_failure(&self, drive_id: &str) {
        if let Some(metrics) = &self.block_device_metrics {
            metrics.record_update_failure_for_drive(drive_id);
        }
    }

    fn fail_runtime_block_mutation(&self, error: &DriveRuntimeMutationError) {
        self.status
            .record(BootRunLoopWorkerStatus::Failed(error.to_string()));
        self.admission.shutdown();
        self.pause_gate.shutdown();
        let _ = self.control.request_stop();
    }

    fn fail_terminal_block_update(&self, error: &DriveUpdateError) {
        self.status
            .record(BootRunLoopWorkerStatus::Failed(error.to_string()));
        self.admission.shutdown();
        self.pause_gate.shutdown();
        let _ = self.control.request_stop();
    }

    fn fail_runtime_pmem_mutation(&self, error: &PmemRuntimeMutationError) {
        self.status
            .record(BootRunLoopWorkerStatus::Failed(error.to_string()));
        self.admission.shutdown();
        self.pause_gate.shutdown();
        let _ = self.control.request_stop();
    }

    fn fail_runtime_network_mutation(&self, error: &NetworkRuntimeMutationError) {
        self.status
            .record(BootRunLoopWorkerStatus::Failed(error.to_string()));
        self.admission.shutdown();
        self.pause_gate.shutdown();
        let _ = self.control.request_stop();
    }

    fn stop_and_join(&mut self) {
        let Some(worker) = self.worker.take() else {
            return;
        };

        // Snapshot memory I/O is cooperative. Signal it before shutdown can
        // wait for a paused worker that currently owns the snapshot lease.
        self.cancel_active_snapshot_capture();
        let was_paused = matches!(self.status(), BootRunLoopWorkerStatus::Paused);
        let stop_requested = self.control.request_stop().is_ok();
        self.admission.shutdown();
        self.pause_gate.shutdown();
        drop(self.session_release_sender.take());

        // A stop error can mean an in-flight vCPU run was not canceled; avoid
        // turning cleanup into an unbounded join in that error path.
        if stop_requested || was_paused || worker.is_finished() {
            let _ = worker.join();
        }
    }
}

impl<S> BootRunLoopSupervisor<S>
where
    S: NativeV1SnapshotCaptureSession,
{
    fn capture_native_v1_snapshot_with_guard(
        session: &S,
        drive_config: &DriveConfig,
        serial_config: &SerialConfig,
        guard: &S::SnapshotAuxiliaryQuiescenceGuard,
        mut output: BoxedNativeV1SnapshotMemoryOutput,
        cancellation: &NativeV1SnapshotCaptureCancellation,
    ) -> Result<S::SnapshotBundle, NativeV1SnapshotCaptureError> {
        let result = (|| {
            if cancellation.is_cancelled() {
                return Err(native_v1_snapshot_cancelled(
                    NativeV1SnapshotCaptureStage::State(
                        HvfArm64BootSnapshotV1CaptureStage::CacheManifest,
                    ),
                ));
            }
            let state = session.capture_native_v1_state(
                drive_config,
                serial_config,
                guard,
                Instant::now(),
                cancellation,
            )?;
            let memory = session.native_v1_guest_memory()?;
            let binding = write_snapshot_memory_image_with_cancel(memory, &mut output, |_stage| {
                cancellation.is_cancelled()
            })
            .map_err(|source| match source {
                SnapshotMemoryWriteError::Cancelled { stage } => {
                    native_v1_snapshot_cancelled(NativeV1SnapshotCaptureStage::Memory(stage))
                }
                source => NativeV1SnapshotCaptureError::MemoryWrite { source },
            })?;
            if cancellation.is_cancelled() {
                return Err(native_v1_snapshot_cancelled(
                    NativeV1SnapshotCaptureStage::Bundle,
                ));
            }
            let bundle = session.bind_native_v1_snapshot(binding, state)?;
            if cancellation.is_cancelled() {
                return Err(native_v1_snapshot_cancelled(
                    NativeV1SnapshotCaptureStage::Bundle,
                ));
            }
            Ok(bundle)
        })();
        // The consumed output must be closed before retry publication is
        // re-enabled, on both success and every recoverable failure.
        drop(output);
        result
    }

    fn capture_native_v1_snapshot(
        &self,
        drive_config: &DriveConfig,
        serial_config: &SerialConfig,
        output: BoxedNativeV1SnapshotMemoryOutput,
        cancellation: NativeV1SnapshotCaptureCancellation,
    ) -> Result<S::SnapshotBundle, NativeV1SnapshotCaptureError> {
        let drive_config = drive_config.clone();
        let serial_config = serial_config.clone();
        let active_capture = self.register_snapshot_capture(cancellation.clone())?;
        if !cancellation.begin_operation() {
            return Err(native_v1_snapshot_cancelled(
                NativeV1SnapshotCaptureStage::State(
                    HvfArm64BootSnapshotV1CaptureStage::CacheManifest,
                ),
            ));
        }

        self.run_snapshot_quiesced(move |session| {
            // Keep shutdown cancellation registered with the worker-owned
            // operation even if the synchronous response receiver is dropped.
            let _active_capture = active_capture;
            let guard = session
                .quiesce_snapshot_auxiliary_work()
                .map_err(|source| NativeV1SnapshotCaptureError::Auxiliary { source })?;
            let result = Self::capture_native_v1_snapshot_with_guard(
                session,
                &drive_config,
                &serial_config,
                &guard,
                output,
                &cancellation,
            );
            drop(guard);
            result
        })
        .map_err(native_snapshot_capture_error_from_boot_run_loop_command)
    }

    fn publish_native_v1_snapshot(
        &self,
        drive_config: &DriveConfig,
        serial_config: &SerialConfig,
        paths: &SnapshotArtifactPaths,
        cancellation: NativeV1SnapshotCaptureCancellation,
    ) -> Result<SnapshotPublicationOutcome, Box<NativeV1SnapshotPublicationTransactionError>> {
        self.publish_native_v1_snapshot_to_destination(
            drive_config,
            serial_config,
            NativeV1SnapshotPublicationDestination::Paths(paths.clone()),
            cancellation,
        )
    }

    fn publish_native_v1_snapshot_to(
        &self,
        drive_config: &DriveConfig,
        serial_config: &SerialConfig,
        outputs: SnapshotArtifactOutputs,
        cancellation: NativeV1SnapshotCaptureCancellation,
    ) -> Result<SnapshotPublicationOutcome, Box<NativeV1SnapshotPublicationTransactionError>> {
        self.publish_native_v1_snapshot_to_destination(
            drive_config,
            serial_config,
            NativeV1SnapshotPublicationDestination::Outputs(outputs),
            cancellation,
        )
    }

    fn publish_native_v1_snapshot_to_destination(
        &self,
        drive_config: &DriveConfig,
        serial_config: &SerialConfig,
        destination: NativeV1SnapshotPublicationDestination,
        cancellation: NativeV1SnapshotCaptureCancellation,
    ) -> Result<SnapshotPublicationOutcome, Box<NativeV1SnapshotPublicationTransactionError>> {
        let drive_config = drive_config.clone();
        let serial_config = serial_config.clone();
        let active_capture = self
            .register_snapshot_capture(cancellation.clone())
            .map_err(native_v1_snapshot_transaction_error_before_staging)?;
        if !cancellation.begin_operation() {
            return Err(native_v1_snapshot_transaction_error_before_staging(
                native_v1_snapshot_cancelled(NativeV1SnapshotCaptureStage::State(
                    HvfArm64BootSnapshotV1CaptureStage::CacheManifest,
                )),
            ));
        }
        let completion_cancellation = cancellation.clone();
        let terminal_status = Arc::clone(&self.status);
        let terminal_admission = Arc::clone(&self.admission);
        let terminal_pause_gate = Arc::clone(&self.pause_gate);

        self.run_snapshot_quiesced_preserving_result_if(
            move |session| {
                // Keep shutdown cancellation registered with every publication
                // phase even if the synchronous response receiver is dropped.
                let _active_capture = active_capture;
                let guard = session
                    .quiesce_snapshot_auxiliary_work()
                    .map_err(|source| {
                        native_v1_snapshot_transaction_error_before_staging(
                            NativeV1SnapshotCaptureError::Auxiliary { source },
                        )
                    })?;
                let result = destination.publish(|writer| {
                    let bundle = Self::capture_native_v1_snapshot_with_guard(
                        session,
                        &drive_config,
                        &serial_config,
                        &guard,
                        Box::new(writer),
                        &cancellation,
                    )
                    .map_err(NativeV1SnapshotPublicationProducerError::Capture)?;
                    let record = require_native_v1_composite_record(
                        S::native_v1_snapshot_commit_record(bundle),
                    )?;
                    if !cancellation.try_seal_commit() {
                        return Err(NativeV1SnapshotPublicationProducerError::Capture(
                            native_v1_snapshot_cancelled(NativeV1SnapshotCaptureStage::CommitSeal),
                        ));
                    }
                    Ok(record)
                });
                if let Ok(outcome) = &result
                    && let Err(source) = session.native_v1_snapshot_published(outcome)
                {
                    terminal_status.record(BootRunLoopWorkerStatus::Failed(source.to_string()));
                    terminal_admission.shutdown();
                    terminal_pause_gate.shutdown();
                    let _ = session.run_loop_control().request_stop();
                }
                drop(guard);
                result.map_err(Box::new)
            },
            move || completion_cancellation.is_commit_sealed(),
        )
        .map_err(native_snapshot_publication_error_from_boot_run_loop_command)
    }
}

fn native_v1_snapshot_cancelled(
    stage: NativeV1SnapshotCaptureStage,
) -> NativeV1SnapshotCaptureError {
    NativeV1SnapshotCaptureError::Cancelled { stage }
}

fn native_v1_snapshot_transaction_error_before_staging(
    source: NativeV1SnapshotCaptureError,
) -> Box<NativeV1SnapshotPublicationTransactionError> {
    Box::new(SnapshotPublicationTransactionError::from_producer(
        NativeV1SnapshotPublicationProducerError::Capture(source),
    ))
}

fn require_native_v1_composite_record(
    record: SnapshotCommitRecord,
) -> Result<SnapshotCommitRecord, NativeV1SnapshotPublicationProducerError> {
    if record.kind() != SnapshotCommitKind::Composite {
        return Err(NativeV1SnapshotPublicationProducerError::NonCompositeCommit);
    }
    Ok(record)
}

impl
    BootRunLoopSupervisor<
        ProcessHvfBootSession<OwnedHvfArm64BootSession, ProcessNetworkPacketIoProvider>,
    >
{
    pub(crate) fn capture_ready_serial_state(
        &self,
        config: SerialConfig,
    ) -> Result<bangbang_runtime::serial::CaptureReadySerialState, HvfArm64BootSerialCaptureError>
    {
        self.run_snapshot_quiesced(move |session| {
            let guard = session
                .quiesce_snapshot_auxiliary_work()
                .map_err(|_| HvfArm64BootSerialCaptureError::OwnerUnavailable)?;
            let result = session.capture_ready_serial_state(config, &guard);
            drop(guard);
            result
        })
        .map_err(serial_capture_error_from_boot_run_loop_command)
    }

    pub(crate) fn capture_ready_balloon_state(
        &self,
        config: Option<BalloonConfig>,
    ) -> Result<Option<HvfArm64BootBalloonCaptureState>, HvfArm64BootBalloonCaptureError> {
        self.run_snapshot_quiesced(move |session| {
            let guard = session
                .quiesce_snapshot_auxiliary_work()
                .map_err(|_| HvfArm64BootBalloonCaptureError::OwnerUnavailable)?;
            let result = session.capture_ready_balloon_state(config, &guard);
            drop(guard);
            result
        })
        .map_err(balloon_capture_error_from_boot_run_loop_command)
    }

    pub(crate) fn capture_ready_memory_hotplug_state(
        &self,
        config: Option<MemoryHotplugConfig>,
    ) -> Result<Option<HvfArm64BootMemoryHotplugCaptureState>, HvfArm64BootMemoryHotplugCaptureError>
    {
        self.run_snapshot_quiesced(move |session| {
            let guard = session
                .quiesce_snapshot_auxiliary_work()
                .map_err(|_| HvfArm64BootMemoryHotplugCaptureError::OwnerUnavailable)?;
            let result = session.capture_ready_memory_hotplug_state(config, &guard);
            drop(guard);
            result
        })
        .map_err(memory_hotplug_capture_error_from_boot_run_loop_command)
    }

    pub(crate) fn capture_ready_entropy_state(
        &self,
        config: Option<EntropyConfig>,
    ) -> Result<Option<HvfArm64BootEntropyCaptureState>, HvfArm64BootEntropyCaptureError> {
        self.run_snapshot_quiesced(move |session| {
            let guard = session
                .quiesce_snapshot_auxiliary_work()
                .map_err(|_| HvfArm64BootEntropyCaptureError::OwnerUnavailable)?;
            let result = session.capture_ready_entropy_state_at(config, &guard, Instant::now());
            drop(guard);
            result
        })
        .map_err(entropy_capture_error_from_boot_run_loop_command)
    }

    pub(crate) fn capture_ready_network_state(
        &self,
        vmnet_authority: ProcessVmnetAuthority,
        configs: Vec<NetworkInterfaceConfig>,
        mmds_config: Option<MmdsConfig>,
        mmds_state: MmdsStateHandle,
    ) -> Result<ProcessCaptureReadyNetworkState, ProcessCaptureReadyNetworkError> {
        self.run_snapshot_quiesced(move |session| {
            let guard = session
                .quiesce_snapshot_auxiliary_work()
                .map_err(|_| ProcessCaptureReadyNetworkError::OwnerUnavailable)?;
            let result = session.capture_ready_network_state_at(
                vmnet_authority,
                &configs,
                mmds_config.as_ref(),
                &mmds_state,
                &guard,
                Instant::now(),
            );
            drop(guard);
            result
        })
        .map_err(network_capture_error_from_boot_run_loop_command)
    }

    fn preflight_capture_ready_vsock(
        &self,
        config: Option<VsockConfig>,
        cancellation: NativeV1SnapshotCaptureCancellation,
    ) -> Result<Option<HvfArm64BootVsockCaptureState>, HvfArm64BootVsockCaptureError> {
        let expected_metrics = self.vsock_device_metrics.clone().ok_or_else(|| {
            HvfArm64BootVsockCaptureError::owner_unavailable(
                HvfArm64BootVsockCaptureDisposition::Terminal,
            )
        })?;
        let active_capture = self
            .register_snapshot_capture(cancellation.clone())
            .map_err(|_| {
                HvfArm64BootVsockCaptureError::owner_unavailable(
                    HvfArm64BootVsockCaptureDisposition::Recoverable,
                )
            })?;
        if !cancellation.begin_operation() {
            return Err(HvfArm64BootVsockCaptureError::cancelled(
                HvfArm64BootVsockCaptureStage::Inventory,
            ));
        }

        let result = self.run_snapshot_quiesced(move |session| {
            let _active_capture = active_capture;
            let guard = session.quiesce_snapshot_auxiliary_work().map_err(|_| {
                HvfArm64BootVsockCaptureError::owner_unavailable(
                    HvfArm64BootVsockCaptureDisposition::Terminal,
                )
            })?;
            let result = session.capture_ready_vsock_state_with_cancel(
                config,
                &expected_metrics,
                &guard,
                &cancellation,
            );
            drop(guard);
            result
        });
        let result = result.map_err(vsock_capture_error_from_boot_run_loop_command);
        if let Err(source) = &result
            && source.is_terminal()
        {
            self.status.record(BootRunLoopWorkerStatus::Failed(
                "terminal vsock capture failure".to_string(),
            ));
            self.admission.shutdown();
            self.pause_gate.shutdown();
            let _ = self.control.request_stop();
        }
        result
    }

    fn preflight_capture_ready_storage(
        &self,
        configs: CaptureReadyStorageConfigs,
        cancellation: NativeV1SnapshotCaptureCancellation,
    ) -> Result<(), HvfArm64BootStorageCaptureError> {
        let active_capture = self
            .register_snapshot_capture(cancellation.clone())
            .map_err(|_| HvfArm64BootStorageCaptureError::owner_unavailable())?;
        if !cancellation.begin_operation() {
            return Err(HvfArm64BootStorageCaptureError::cancelled());
        }
        let result = self.run_snapshot_quiesced(move |session| {
            let _active_capture = active_capture;
            let guard = session
                .quiesce_snapshot_auxiliary_work()
                .map_err(|_| HvfArm64BootStorageCaptureError::owner_unavailable())?;
            let result = session.capture_ready_storage_state_at_with_cancel(
                &configs,
                &guard,
                Instant::now(),
                &cancellation,
            );
            drop(guard);
            result
        });
        if let Err(BootRunLoopCommandError::Command { source }) = &result
            && source.terminal()
        {
            self.status.record(BootRunLoopWorkerStatus::Failed(
                "terminal storage capture failure".to_string(),
            ));
            self.admission.shutdown();
            self.pause_gate.shutdown();
            let _ = self.control.request_stop();
        }
        result.map_err(storage_capture_error_from_boot_run_loop_command)
    }

    #[expect(
        dead_code,
        reason = "standalone device capture remains a focused internal diagnostic seam"
    )]
    pub(crate) fn capture_snapshot_v1_device_state(
        &self,
        drive_config: &DriveConfig,
        serial_config: &SerialConfig,
    ) -> Result<SnapshotV1DeviceState, BackendError> {
        let drive_config = drive_config.clone();
        let serial_config = serial_config.clone();
        self.run_snapshot_quiesced(move |session| {
            let guard = session.quiesce_snapshot_auxiliary_work()?;
            let now = Instant::now();
            session
                .capture_snapshot_v1_device_state_at(&drive_config, &serial_config, &guard, now)
                .map_err(|error| {
                    BackendError::Hypervisor(format!(
                        "failed to capture native-v1 device state: {error}"
                    ))
                })
        })
        .map_err(lifecycle_error_from_boot_run_loop_command)
    }

    #[expect(
        dead_code,
        reason = "standalone bundle capture remains an internal diagnostic seam"
    )]
    pub(crate) fn capture_snapshot_v1_bundle(
        &self,
        drive_config: &DriveConfig,
        serial_config: &SerialConfig,
        output: BoxedNativeV1SnapshotMemoryOutput,
        cancellation: NativeV1SnapshotCaptureCancellation,
    ) -> Result<HvfSnapshotV1Bundle, NativeV1SnapshotCaptureError> {
        self.capture_native_v1_snapshot(drive_config, serial_config, output, cancellation)
    }
}

