    #[derive(Debug)]
    struct RuntimeNetworkTransactionProvider {
        events: Arc<Mutex<Vec<String>>>,
        live_iface: Option<String>,
        prepare_error: Option<NetworkRuntimeMutationError>,
        take_fails: bool,
        stop_fails: bool,
        restore_fails: bool,
    }

    impl RuntimeNetworkTransactionProvider {
        fn empty(events: Arc<Mutex<Vec<String>>>) -> Self {
            Self {
                events,
                live_iface: None,
                prepare_error: None,
                take_fails: false,
                stop_fails: false,
                restore_fails: false,
            }
        }

        fn with_live_iface(events: Arc<Mutex<Vec<String>>>, iface_id: &str) -> Self {
            Self {
                live_iface: Some(iface_id.to_string()),
                ..Self::empty(events)
            }
        }

        fn with_take_failure(mut self) -> Self {
            self.take_fails = true;
            self
        }

        fn with_stop_failure(mut self) -> Self {
            self.stop_fails = true;
            self
        }

        fn with_restore_failure(mut self) -> Self {
            self.restore_fails = true;
            self
        }
    }

    impl Arm64BootNetworkPacketIoProvider for RuntimeNetworkTransactionProvider {
        fn packet_io(
            &mut self,
            _interface: Arm64BootNetworkInterface<'_>,
        ) -> Result<Arm64BootNetworkPacketIo<'_>, Arm64BootNetworkPacketIoError> {
            Err(Arm64BootNetworkPacketIoError::new(
                "transaction test does not dispatch packets",
            ))
        }
    }

    impl ProcessRuntimeNetworkPacketIoProvider for RuntimeNetworkTransactionProvider {
        type PreparedEntry = RuntimeNetworkTransactionEntry;
        type PublishedEntry = String;
        type RemovedEntry = RuntimeNetworkTransactionEntry;

        fn prepare_runtime_entry(
            &mut self,
            config: &NetworkInterfaceConfig,
            _authority: ProcessVmnetAuthority,
        ) -> Result<(Self::PreparedEntry, NetworkDeviceProfile), NetworkRuntimeMutationError>
        {
            push_recorded_event(
                &self.events,
                format!("provider-prepare:{}", config.iface_id()),
            );
            if let Some(error) = self.prepare_error.clone() {
                return Err(error);
            }
            Ok((
                RuntimeNetworkTransactionEntry {
                    iface_id: config.iface_id().to_string(),
                    events: Arc::clone(&self.events),
                    stop_fails: self.stop_fails,
                },
                NetworkDeviceProfile::from_config(config),
            ))
        }

        fn publish_prepared_entry(
            &mut self,
            prepared: Self::PreparedEntry,
        ) -> Self::PublishedEntry {
            push_recorded_event(
                &self.events,
                format!("provider-publish:{}", prepared.iface_id),
            );
            assert!(self.live_iface.is_none());
            self.live_iface = Some(prepared.iface_id.clone());
            prepared.iface_id
        }

        fn take_published_entry(
            &mut self,
            published: &Self::PublishedEntry,
        ) -> Result<Self::RemovedEntry, ProcessNetworkPacketIoRegistryError> {
            push_recorded_event(&self.events, format!("provider-take-published:{published}"));
            self.take_entry(published)
        }

        fn take_interface_entry(
            &mut self,
            iface_id: &str,
        ) -> Result<Self::RemovedEntry, ProcessNetworkPacketIoRegistryError> {
            push_recorded_event(&self.events, format!("provider-take:{iface_id}"));
            self.take_entry(iface_id)
        }

        fn stop_removed_entry(
            removed: &mut Self::RemovedEntry,
        ) -> Result<(), ProcessNetworkPacketIoStopError> {
            push_recorded_event(
                &removed.events,
                format!("provider-stop:{}", removed.iface_id),
            );
            if removed.stop_fails {
                Err(ProcessNetworkPacketIoStopError::Vmnet {
                    source: VmnetVirtioNetworkPacketIoStopError::StatePoisoned,
                })
            } else {
                Ok(())
            }
        }

        fn restore_removed_entry(
            &mut self,
            removed: Self::RemovedEntry,
        ) -> Result<(), ProcessNetworkPacketIoRegistryError> {
            push_recorded_event(
                &self.events,
                format!("provider-restore:{}", removed.iface_id),
            );
            if self.restore_fails {
                return Err(ProcessNetworkPacketIoRegistryError::Capacity);
            }
            self.live_iface = Some(removed.iface_id);
            Ok(())
        }
    }

    impl RuntimeNetworkTransactionProvider {
        fn take_entry(
            &mut self,
            iface_id: &str,
        ) -> Result<RuntimeNetworkTransactionEntry, ProcessNetworkPacketIoRegistryError> {
            if self.take_fails || self.live_iface.as_deref() != Some(iface_id) {
                return Err(ProcessNetworkPacketIoRegistryError::UnknownInterface);
            }
            self.live_iface = None;
            Ok(RuntimeNetworkTransactionEntry {
                iface_id: iface_id.to_string(),
                events: Arc::clone(&self.events),
                stop_fails: self.stop_fails,
            })
        }
    }

    #[derive(Debug, Clone, PartialEq, Eq)]
    struct RecordingVmnetInterface {
        iface_id: String,
    }

    #[derive(Debug)]
    struct RecordingVmnetPacketIoBackend {
        iface_id: String,
        events: Arc<Mutex<Vec<String>>>,
        packet_callbacks: Arc<Mutex<Vec<(String, VmnetPacketAvailableCallback)>>>,
        record_packet_event_lifecycle: bool,
        start_status: Option<VmnetStatus>,
        stop_status: Option<VmnetStatus>,
        realized_mac: GuestMacAddress,
    }

    impl VmnetInterfaceBackend for RecordingVmnetPacketIoBackend {
        type Interface = RecordingVmnetInterface;

        fn build_interface_descriptor(
            &mut self,
            config: &VmnetInterfaceConfig,
        ) -> Result<VmnetInterfaceDescriptor, VmnetInterfaceDescriptorError> {
            push_recorded_event(
                &self.events,
                format!("descriptor:{}:{}", self.iface_id, config.mode()),
            );
            VmnetInterfaceDescriptor::new(config)
        }

        fn start_interface(
            &mut self,
            _descriptor: &VmnetInterfaceDescriptor,
        ) -> Result<VmnetStartedInterface<Self::Interface>, VmnetInterfaceStartError> {
            push_recorded_event(&self.events, format!("start:{}", self.iface_id));
            if let Some(status) = self.start_status {
                return Err(VmnetInterfaceStartError::Start {
                    source: VmnetError::new(VmnetOperation::StartInterface, status),
                    disposition: VmnetInterfaceStartDisposition::Retryable,
                });
            }

            Ok(VmnetStartedInterface::new(
                RecordingVmnetInterface {
                    iface_id: self.iface_id.clone(),
                },
                VmnetInterfaceParameters::for_test(self.realized_mac, 1500, 2048),
            ))
        }

        fn stop_interface(&mut self, interface: &mut Self::Interface) -> Result<(), VmnetError> {
            push_recorded_event(&self.events, format!("stop:{}", interface.iface_id));
            if let Some(status) = self.stop_status {
                return Err(VmnetError::new(VmnetOperation::StopInterface, status));
            }
            Ok(())
        }

        fn enable_packet_available_callback(
            &mut self,
            interface: &mut Self::Interface,
            callback: VmnetPacketAvailableCallback,
        ) -> Result<(), VmnetError> {
            if self.record_packet_event_lifecycle {
                push_recorded_event(
                    &self.events,
                    format!("packet-events-enable:{}", interface.iface_id),
                );
            }
            self.packet_callbacks
                .lock()
                .expect("recorded callback list should lock")
                .push((interface.iface_id.clone(), callback));
            Ok(())
        }

        fn disable_and_drain_packet_available_callback(
            &mut self,
            interface: &mut Self::Interface,
        ) -> Result<(), VmnetError> {
            if self.record_packet_event_lifecycle {
                push_recorded_event(
                    &self.events,
                    format!("packet-events-disable-drain:{}", interface.iface_id),
                );
            }
            self.packet_callbacks
                .lock()
                .expect("recorded callback list should lock")
                .retain(|(iface_id, _)| iface_id != &interface.iface_id);
            Ok(())
        }
    }

    impl VmnetPacketIoBackend for RecordingVmnetPacketIoBackend {
        type Interface = RecordingVmnetInterface;

        fn read_packet(
            &mut self,
            interface: &mut Self::Interface,
            _packet: &mut VmnetReadPacket<'_>,
        ) -> Result<Option<usize>, VmnetPacketIoError> {
            push_recorded_event(&self.events, format!("read:{}", interface.iface_id));
            Ok(None)
        }

        fn write_packet(
            &mut self,
            interface: &mut Self::Interface,
            _packet: &mut VmnetWritePacket<'_>,
        ) -> Result<(), VmnetPacketIoError> {
            push_recorded_event(&self.events, format!("write:{}", interface.iface_id));
            Ok(())
        }
    }

    #[derive(Debug, Default)]
    struct RecordingVmnetPacketIoBackendFactory {
        events: Arc<Mutex<Vec<String>>>,
        packet_callbacks: Arc<Mutex<Vec<(String, VmnetPacketAvailableCallback)>>>,
        record_packet_event_lifecycle: bool,
        start_statuses: VecDeque<Option<VmnetStatus>>,
        stop_statuses: VecDeque<Option<VmnetStatus>>,
        realized_macs: VecDeque<GuestMacAddress>,
        next_realized_mac: u8,
    }

    impl RecordingVmnetPacketIoBackendFactory {
        fn events(&self) -> Arc<Mutex<Vec<String>>> {
            Arc::clone(&self.events)
        }

        fn packet_callbacks(&self) -> Arc<Mutex<Vec<(String, VmnetPacketAvailableCallback)>>> {
            Arc::clone(&self.packet_callbacks)
        }

        fn recording_packet_event_lifecycle(mut self) -> Self {
            self.record_packet_event_lifecycle = true;
            self
        }

        fn with_next_start_status(mut self, status: Option<VmnetStatus>) -> Self {
            self.start_statuses.push_back(status);
            self
        }

        fn with_next_stop_status(mut self, status: Option<VmnetStatus>) -> Self {
            self.stop_statuses.push_back(status);
            self
        }

        fn with_next_realized_mac(mut self, mac: GuestMacAddress) -> Self {
            self.realized_macs.push_back(mac);
            self
        }
    }

    impl ProcessVmnetPacketIoBackendFactory for RecordingVmnetPacketIoBackendFactory {
        type Backend = RecordingVmnetPacketIoBackend;

        fn new_backend(&mut self, iface_id: &str) -> Self::Backend {
            push_recorded_event(&self.events, format!("backend:{iface_id}"));
            self.next_realized_mac = self.next_realized_mac.saturating_add(1);
            RecordingVmnetPacketIoBackend {
                iface_id: iface_id.to_string(),
                events: Arc::clone(&self.events),
                packet_callbacks: Arc::clone(&self.packet_callbacks),
                record_packet_event_lifecycle: self.record_packet_event_lifecycle,
                start_status: self.start_statuses.pop_front().unwrap_or(None),
                stop_status: self.stop_statuses.pop_front().unwrap_or(None),
                realized_mac: self.realized_macs.pop_front().unwrap_or_else(|| {
                    GuestMacAddress::from_bytes([0x02, 0, 0, 0, 0, self.next_realized_mac])
                }),
            }
        }
    }

    fn push_recorded_event(events: &Arc<Mutex<Vec<String>>>, event: String) {
        events
            .lock()
            .expect("recorded event log should lock")
            .push(event);
    }

    fn recorded_events(events: &Arc<Mutex<Vec<String>>>) -> Vec<String> {
        events
            .lock()
            .expect("recorded event log should lock")
            .clone()
    }

    fn recorded_packet_callback(
        callbacks: &Arc<Mutex<Vec<(String, VmnetPacketAvailableCallback)>>>,
        iface_id: &str,
    ) -> VmnetPacketAvailableCallback {
        callbacks
            .lock()
            .expect("recorded callback list should lock")
            .iter()
            .find(|(candidate, _)| candidate == iface_id)
            .map(|(_, callback)| callback.clone())
            .expect("recorded packet callback should exist")
    }

    fn network_configs(
        configs: impl IntoIterator<Item = (&'static str, &'static str)>,
    ) -> Vec<NetworkInterfaceConfig> {
        let mut network_configs = NetworkInterfaceConfigs::new();
        for (iface_id, host_dev_name) in configs {
            network_configs
                .insert(NetworkInterfaceConfigInput::new(
                    iface_id,
                    iface_id,
                    host_dev_name,
                ))
                .expect("network config should insert");
        }

        network_configs.as_slice().to_vec()
    }

    fn validated_network_configs(count: usize) -> Vec<NetworkInterfaceConfig> {
        (0..count)
            .map(|index| {
                let iface_id = format!("eth{index}");
                NetworkInterfaceConfigInput::new(iface_id.clone(), iface_id, "vmnet:shared")
                    .validate()
                    .expect("individual network config should validate")
            })
            .collect()
    }

    fn test_boot_network_device() -> Arm64BootNetworkDevice {
        let mut configs = NetworkInterfaceConfigs::new();
        configs
            .insert(NetworkInterfaceConfigInput::new("eth0", "eth0", "tap0"))
            .expect("test network config should insert");
        let prepared = PreparedNetworkDevices::from_configs(&configs)
            .expect("test network device should prepare");
        let devices = prepared
            .register_mmio(NetworkMmioLayout::new(
                DEFAULT_NETWORK_MMIO_BASE,
                DEFAULT_NETWORK_MMIO_REGION_ID,
            ))
            .expect("test network MMIO should register");
        let (_dispatcher, mut registrations) = devices.into_parts();
        let registration = registrations.remove(0);
        let region = registration.region();

        Arm64BootNetworkDevice {
            registration,
            fdt_device: Arm64FdtVirtioMmioDevice {
                region: Arm64FdtRegion {
                    base: region.range().start().raw_value(),
                    size: region.range().size(),
                },
                interrupt_line: GuestInterruptLine::new(32)
                    .expect("test interrupt line should be valid"),
            },
        }
    }

