    #[test]
    fn broad_snapshot_profile_runs_complete_storage_preflight_before_profile_rejection() {
        let state_path = missing_temp_child_path("broad-storage.state");
        let memory_path = state_path.with_file_name("broad-storage.memory");
        let parent = state_path
            .parent()
            .expect("missing broad snapshot path should have a parent");
        let mut vmm = configured_vmm(FakeStarter::success(160));
        let owner = contained_vmnet_authority_for_session(0x61, VmnetAuthority::denied());
        vmm.vmnet_authority = owner;
        vmm.handle_action(VmmAction::PutDrive(
            DriveConfigInput::new("root", "root", "/private/root", true)
                .with_is_read_only(true)
                .with_io_engine(DriveIoEngine::Sync),
        ))
        .expect("broad snapshot root should configure");
        vmm.handle_action(VmmAction::PutDrive(
            DriveConfigInput::new("data", "data", "/private/data", false)
                .with_io_engine(DriveIoEngine::Async),
        ))
        .expect("broad snapshot Async drive should configure");
        vmm.handle_action(VmmAction::PutPmem(PmemConfigInput::new(
            "pmem0",
            "/private/pmem",
        )))
        .expect("broad snapshot pmem should configure");
        vmm.handle_action(VmmAction::PutBalloon(
            BalloonConfigInput::new(8, true)
                .with_stats_polling_interval_s(1)
                .with_free_page_hinting(true)
                .with_free_page_reporting(true),
        ))
        .expect("broad snapshot balloon should configure");
        vmm.handle_action(VmmAction::PutMemoryHotplug(memory_hotplug_config_input()))
            .expect("broad snapshot memory hotplug should configure");
        vmm.handle_action(VmmAction::PutEntropy(EntropyConfigInput::new()))
            .expect("broad snapshot entropy should configure");
        vmm.handle_action(VmmAction::PutNetworkInterface(
            NetworkInterfaceConfigInput::new("eth0", "eth0", "vmnet:shared"),
        ))
        .expect("broad snapshot network should configure");
        vmm.handle_action(VmmAction::PutMmdsConfig(MmdsConfigInput::new(vec![
            "eth0".to_string(),
        ])))
        .expect("broad snapshot MMDS should configure");
        vmm.handle_action(VmmAction::PutVsock(VsockConfigInput::new(
            42,
            "/private/broad-vsock.sock",
        )))
        .expect("broad snapshot vsock should configure");
        vmm.handle_action(VmmAction::InstanceStart)
            .expect("broad snapshot fake session should start");
        vmm.handle_action(VmmAction::Pause)
            .expect("broad snapshot fake session should pause");

        let error = vmm
            .handle_action(VmmAction::CreateSnapshot(SnapshotCreateInput::new(
                SnapshotType::Full,
                &state_path,
                &memory_path,
            )))
            .expect_err("broad profile should reject only after live storage preflight");

        assert_eq!(error, VmmActionError::SnapshotUnsupported);
        assert_eq!(vmm.starter.snapshot_storage_preflight_calls, 1);
        let captured_configs = vmm
            .starter
            .last_snapshot_storage_configs
            .as_ref()
            .expect("storage preflight should receive the complete config inventory");
        assert_eq!(captured_configs.drives(), vmm.controller.drive_configs());
        assert_eq!(captured_configs.pmem(), vmm.controller.pmem_configs());
        assert_eq!(vmm.starter.snapshot_balloon_preflight_calls, 1);
        assert_eq!(
            vmm.starter.last_snapshot_balloon_config,
            Some(vmm.controller.balloon_config())
        );
        assert_eq!(vmm.starter.snapshot_memory_hotplug_preflight_calls, 1);
        assert_eq!(
            vmm.starter.last_snapshot_memory_hotplug_config,
            Some(vmm.controller.memory_hotplug_config())
        );
        assert_eq!(vmm.starter.snapshot_entropy_preflight_calls, 1);
        assert_eq!(
            vmm.starter.last_snapshot_entropy_config,
            Some(vmm.controller.entropy_config())
        );
        assert_eq!(vmm.starter.snapshot_serial_preflight_calls, 1);
        assert_eq!(
            vmm.starter.last_snapshot_serial_config,
            Some(vmm.controller.serial_config().clone())
        );
        assert_eq!(vmm.starter.snapshot_network_preflight_calls, 1);
        assert_eq!(vmm.starter.last_start_vmnet_authority, Some(owner));
        assert_eq!(vmm.starter.last_snapshot_vmnet_authority, Some(owner));
        assert_eq!(
            vmm.starter.last_snapshot_network_configs.as_deref(),
            Some(vmm.controller.network_interface_configs())
        );
        assert_eq!(
            vmm.starter.last_snapshot_mmds_config,
            Some(
                vmm.controller
                    .mmds_config()
                    .expect("MMDS state should lock")
            )
        );
        assert!(
            vmm.starter
                .last_snapshot_mmds_state
                .as_ref()
                .expect("network preflight should receive MMDS ownership")
                .shares_state_with(&vmm.controller.mmds_state_handle())
        );
        assert_eq!(vmm.starter.snapshot_vsock_preflight_calls, 1);
        assert_eq!(
            vmm.starter.last_snapshot_vsock_config.as_ref(),
            Some(&vmm.controller.vsock_config().cloned())
        );
        assert!(
            vmm.starter
                .last_snapshot_vsock_cancellation
                .as_ref()
                .expect("vsock preflight should receive snapshot cancellation ownership")
                .same_operation(&vmm.snapshot_capture_cancellation)
        );
        assert_eq!(
            vmm.starter.snapshot_preflight_trace,
            [
                "storage",
                "balloon",
                "memory-hotplug",
                "entropy",
                "serial",
                "network",
                "vsock",
            ]
        );
        let session = vmm
            .started_session
            .as_ref()
            .expect("rejected broad snapshot should retain its paused session");
        assert_eq!(session.native_snapshot_publication_count, 0);
        assert_eq!(session.native_snapshot_producer_count, 0);
        assert!(!state_path.exists());
        assert!(!memory_path.exists());
        assert!(!parent.exists());
    }

    #[test]
    fn aggregate_remaining_device_snapshot_preflight_failures_preserve_order_and_reuse() {
        #[derive(Clone, Copy)]
        enum FailureStage {
            Storage,
            Balloon,
            MemoryHotplug,
            Entropy,
            Serial,
            Network,
            Vsock,
        }

        const COMPLETE_TRACE: &[&str] = &[
            "storage",
            "balloon",
            "memory-hotplug",
            "entropy",
            "serial",
            "network",
            "vsock",
        ];
        let cases = [
            (
                FailureStage::Storage,
                "storage",
                FakeStarter::success(170).with_snapshot_storage_preflight_failure(
                    HvfArm64BootStorageCaptureError::owner_unavailable(),
                ),
                &COMPLETE_TRACE[..1],
            ),
            (
                FailureStage::Balloon,
                "balloon",
                FakeStarter::success(171).with_snapshot_balloon_preflight_failure(),
                &COMPLETE_TRACE[..2],
            ),
            (
                FailureStage::MemoryHotplug,
                "memory-hotplug",
                FakeStarter::success(172).with_snapshot_memory_hotplug_preflight_failure(),
                &COMPLETE_TRACE[..3],
            ),
            (
                FailureStage::Entropy,
                "entropy",
                FakeStarter::success(173).with_snapshot_entropy_preflight_failure(),
                &COMPLETE_TRACE[..4],
            ),
            (
                FailureStage::Serial,
                "serial",
                FakeStarter::success(174).with_snapshot_serial_preflight_failure(),
                &COMPLETE_TRACE[..5],
            ),
            (
                FailureStage::Network,
                "network",
                FakeStarter::success(175).with_snapshot_network_preflight_failure(),
                &COMPLETE_TRACE[..6],
            ),
            (
                FailureStage::Vsock,
                "vsock",
                FakeStarter::success(176).with_snapshot_vsock_preflight_failure(),
                COMPLETE_TRACE,
            ),
        ];

        for (stage, name, starter, expected_failed_trace) in cases {
            let state_path = missing_temp_child_path(&format!("aggregate-{name}.state"));
            let memory_path = state_path.with_file_name(format!("aggregate-{name}.memory"));
            let parent = state_path
                .parent()
                .expect("aggregate snapshot path should have a parent");
            let mut vmm = configured_vmm(starter);
            vmm.handle_action(VmmAction::PutDrive(
                DriveConfigInput::new("root", "root", "/private/root", true)
                    .with_is_read_only(true)
                    .with_io_engine(DriveIoEngine::Sync),
            ))
            .expect("aggregate snapshot root should configure");
            vmm.handle_action(VmmAction::PutBalloon(
                BalloonConfigInput::new(8, true)
                    .with_stats_polling_interval_s(1)
                    .with_free_page_hinting(true)
                    .with_free_page_reporting(true),
            ))
            .expect("aggregate snapshot balloon should configure");
            vmm.handle_action(VmmAction::PutMemoryHotplug(memory_hotplug_config_input()))
                .expect("aggregate snapshot memory hotplug should configure");
            vmm.handle_action(VmmAction::PutEntropy(EntropyConfigInput::new()))
                .expect("aggregate snapshot entropy should configure");
            vmm.handle_action(VmmAction::PutSerial(
                SerialConfigInput::new().with_rate_limiter(
                    bangbang_runtime::serial::SerialRateLimiterConfig::new(8, Some(16), 100),
                ),
            ))
            .expect("aggregate snapshot serial should configure");
            vmm.handle_action(VmmAction::InstanceStart)
                .expect("aggregate snapshot fake session should start");
            vmm.handle_action(VmmAction::Pause)
                .expect("aggregate snapshot fake session should pause");

            let drive_configs = vmm.controller.drive_configs().to_vec();
            let balloon_config = vmm.controller.balloon_config();
            let memory_hotplug_config = vmm.controller.memory_hotplug_config();
            let entropy_config = vmm.controller.entropy_config();
            let serial_config = vmm.controller.serial_config().clone();
            let input = SnapshotCreateInput::new(SnapshotType::Full, &state_path, &memory_path);
            let error = vmm
                .handle_action(VmmAction::CreateSnapshot(input.clone()))
                .expect_err("injected aggregate preflight failure should be reported");

            assert!(
                matches!(error, VmmActionError::SnapshotCreate(_)),
                "{name} should retain its typed snapshot-create classification: {error:?}"
            );
            assert_eq!(vmm.starter.snapshot_preflight_trace, expected_failed_trace);
            assert_eq!(vmm.instance_info().state, InstanceState::Paused);
            assert_eq!(vmm.controller.drive_configs(), drive_configs);
            assert_eq!(vmm.controller.balloon_config(), balloon_config);
            assert_eq!(
                vmm.controller.memory_hotplug_config(),
                memory_hotplug_config
            );
            assert_eq!(vmm.controller.entropy_config(), entropy_config);
            assert_eq!(vmm.controller.serial_config(), &serial_config);
            assert!(!state_path.exists());
            assert!(!memory_path.exists());
            assert!(!parent.exists());

            match stage {
                FailureStage::Storage => vmm.starter.snapshot_storage_preflight_failure = None,
                FailureStage::Balloon => vmm.starter.snapshot_balloon_preflight_failure = false,
                FailureStage::MemoryHotplug => {
                    vmm.starter.snapshot_memory_hotplug_preflight_failure = false;
                }
                FailureStage::Entropy => vmm.starter.snapshot_entropy_preflight_failure = false,
                FailureStage::Serial => vmm.starter.snapshot_serial_preflight_failure = false,
                FailureStage::Network => vmm.starter.snapshot_network_preflight_failure = false,
                FailureStage::Vsock => vmm.starter.snapshot_vsock_preflight_failure = None,
            }

            let retry_error = vmm
                .handle_action(VmmAction::CreateSnapshot(input))
                .expect_err("aggregate retry should traverse every owner before profile rejection");
            assert_eq!(retry_error, VmmActionError::SnapshotUnsupported);
            let mut expected_retry_trace = expected_failed_trace.to_vec();
            expected_retry_trace.extend_from_slice(COMPLETE_TRACE);
            assert_eq!(vmm.starter.snapshot_preflight_trace, expected_retry_trace);
            assert_eq!(vmm.instance_info().state, InstanceState::Paused);
            let session = vmm
                .started_session
                .as_ref()
                .expect("aggregate retry should retain its paused session");
            assert_eq!(session.native_snapshot_publication_count, 0);
            assert_eq!(session.native_snapshot_producer_count, 0);
            assert!(!state_path.exists());
            assert!(!memory_path.exists());
            assert!(!parent.exists());
        }
    }

